#[derive(Parser, Debug)]
#[command(
    name = "am",
    version = env!("CARGO_PKG_VERSION"),
    about = "MCP Agent Mail CLI (Rust)",
    after_help = MCP_TOOL_CLI_CORRECTION_HELP
)]
pub struct Cli {
    #[command(subcommand)]
    pub command: Option<Commands>,
}

#[derive(Subcommand, Debug)]
pub enum Commands {
    /// Run the Agent Mail MCP server over streamable HTTP (with optional TUI).
    #[command(name = "serve-http")]
    ServeHttp {
        #[arg(long)]
        host: Option<String>,
        #[arg(long)]
        port: Option<u16>,
        #[arg(long)]
        path: Option<String>,
        /// Disable bearer token authentication for this run (for local development).
        #[arg(long)]
        no_auth: bool,
        /// Disable the interactive TUI and run headless.
        #[arg(long)]
        no_tui: bool,
        /// Extra Host header to accept (repeatable; also reads HTTP_ALLOWED_HOSTS).
        #[arg(long = "allowed-host", value_name = "HOST")]
        allowed_host: Vec<String>,
        /// Forcibly take over the storage root from an already-running server.
        ///
        /// By default, if another Agent Mail server is LIVE and answering
        /// `/healthz` on this host:port, startup REFUSES (exit 1) rather than
        /// killing the responsive peer. Pass --takeover to SIGTERM/SIGKILL the
        /// existing holder and seize the storage root anyway.
        #[arg(long)]
        takeover: bool,
    },
    /// Run the Agent Mail MCP server over stdio (for direct MCP client launch).
    #[command(name = "serve-stdio")]
    ServeStdio,
    /// Print the machine-readable CLI capabilities contract.
    #[command(name = "capabilities")]
    Capabilities {
        /// Output format: table, json, or toon (default: table).
        #[arg(long, value_parser)]
        format: Option<output::CliOutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
    },
    /// First-turn cockpit for agents: identity, project, runtime hints, and next actions.
    #[command(name = "agent")]
    Agent {
        #[command(subcommand)]
        action: AgentCommand,
    },
    /// Direct alias for `am robot status`.
    #[command(name = "status")]
    Status {
        /// Output format: toon or json.
        #[arg(long, value_parser = parse_robot_snapshot_output_format)]
        format: Option<robot::OutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Project key (absolute path or slug). Falls back to AGENT_MAIL_PROJECT, then CWD.
        #[arg(long)]
        project: Option<String>,
        /// Agent name. Falls back to AGENT_MAIL_AGENT, then AGENT_NAME.
        #[arg(long)]
        agent: Option<String>,
    },
    /// Direct alias for `am robot inbox`.
    #[command(name = "inbox")]
    Inbox {
        /// Output format: toon or json.
        #[arg(long, value_parser = parse_robot_snapshot_output_format)]
        format: Option<robot::OutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Project key (absolute path or slug). Falls back to AGENT_MAIL_PROJECT, then CWD.
        #[arg(long)]
        project: Option<String>,
        /// Agent name. Falls back to AGENT_MAIL_AGENT, then AGENT_NAME.
        #[arg(long)]
        agent: Option<String>,
        /// Show only urgent messages.
        #[arg(long)]
        urgent: bool,
        /// Show only ack-overdue messages.
        #[arg(long)]
        ack_overdue: bool,
        /// Show only unread messages.
        #[arg(long)]
        unread: bool,
        /// Show all messages (no filtering).
        #[arg(long)]
        all: bool,
        /// Maximum messages to return.
        #[arg(long)]
        limit: Option<usize>,
        /// Include message bodies in output.
        #[arg(long)]
        include_bodies: bool,
    },
    /// Direct alias for `am robot reservations`.
    #[command(name = "reservations")]
    Reservations {
        /// Output format: toon or json.
        #[arg(long, value_parser = parse_robot_snapshot_output_format)]
        format: Option<robot::OutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Project key (absolute path or slug). Falls back to AGENT_MAIL_PROJECT, then CWD.
        #[arg(long)]
        project: Option<String>,
        /// Agent name. Falls back to AGENT_MAIL_AGENT, then AGENT_NAME.
        #[arg(long)]
        agent: Option<String>,
        /// Show reservations for all agents, not just the selected agent.
        #[arg(long)]
        all: bool,
        /// Show only conflicting reservations.
        #[arg(long)]
        conflicts: bool,
        /// Warn about reservations expiring within N minutes.
        #[arg(long)]
        expiring: Option<u32>,
    },
    /// Direct alias for `am robot health`.
    #[command(name = "health")]
    Health {
        /// Output format: toon or json.
        #[arg(long, value_parser = parse_robot_snapshot_output_format)]
        format: Option<robot::OutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Project key (absolute path or slug). Falls back to AGENT_MAIL_PROJECT, then CWD.
        #[arg(long)]
        project: Option<String>,
        /// Agent name. Falls back to AGENT_MAIL_AGENT, then AGENT_NAME.
        #[arg(long)]
        agent: Option<String>,
        /// Include the bounded host-pressure section (disk/inodes/load/memory).
        #[arg(long)]
        include_host: bool,
    },
    /// Non-interactive TUI snapshot dump — the freeze escape hatch (I6).
    ///
    /// Returns the same situational snapshot the interactive TUI renders,
    /// fetched live from `/mail/ws-state` when the server is reachable and
    /// falling back to a local SQLite read when the TUI/server appears frozen.
    /// Always exits 0 so an agent can read state instead of killing the process.
    #[command(name = "tui-dump")]
    TuiDump {
        /// Output format: toon or json.
        #[arg(long, value_parser = parse_robot_snapshot_output_format)]
        format: Option<robot::OutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Project key (absolute path or slug). Falls back to AGENT_MAIL_PROJECT, then CWD.
        #[arg(long)]
        project: Option<String>,
        /// Agent name. Falls back to AGENT_MAIL_AGENT, then AGENT_NAME.
        #[arg(long)]
        agent: Option<String>,
    },
    /// Direct alias for `am robot thread`.
    #[command(name = "thread")]
    Thread {
        /// Thread ID.
        id: String,
        /// Output format: toon, json, or md.
        #[arg(long, value_parser = parse_robot_alias_output_format)]
        format: Option<robot::OutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Project key (absolute path or slug). Falls back to AGENT_MAIL_PROJECT, then CWD.
        #[arg(long)]
        project: Option<String>,
        /// Agent name. Falls back to AGENT_MAIL_AGENT, then AGENT_NAME.
        #[arg(long)]
        agent: Option<String>,
        /// Maximum messages in thread.
        #[arg(long)]
        limit: Option<usize>,
        /// Show messages after this timestamp.
        #[arg(long)]
        since: Option<String>,
    },
    /// Check agent inbox for unread messages (for git hooks and editor integrations).
    #[command(name = "check-inbox")]
    CheckInbox {
        /// Agent name to check inbox for (default: AGENT_NAME or AGENT_MAIL_AGENT env var).
        #[arg(long)]
        agent: Option<String>,
        /// Minimum interval between checks in seconds (default: 120, 0 to disable).
        #[arg(long, default_value_t = 120)]
        rate_limit: u64,
        /// Allow a direct SQLite read for co-located setups. Still prefers the
        /// running daemon over HTTP when it is reachable (avoids WAL contention
        /// with the daemon's writer) and only reads SQLite directly when no
        /// daemon is listening.
        #[arg(long)]
        direct: bool,
        /// Output format: table, json, or toon (default: auto-detect).
        #[arg(long, value_parser)]
        format: Option<output::CliOutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Server host for HTTP mode (default: 127.0.0.1).
        #[arg(long, default_value = "127.0.0.1")]
        host: String,
        /// Server port for HTTP mode (default: 8765).
        #[arg(long, default_value_t = 8765)]
        port: u16,
        /// Project key to check (default: AGENT_MAIL_PROJECT env var or current directory).
        #[arg(long)]
        project: Option<String>,
    },
    /// Run the unified local pre-release quality gate.
    #[command(name = "check")]
    Check {
        /// Quick mode: skip long-running perf and E2E gates.
        #[arg(long, short = 'q')]
        quick: bool,
        /// Write JSON report to this path.
        #[arg(long, short = 'r')]
        report: Option<std::path::PathBuf>,
        /// Output format: table, json, or toon (default: auto-detect).
        #[arg(long, value_parser)]
        format: Option<output::CliOutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Run independent gates in parallel (faster execution).
        #[arg(long, short = 'p')]
        parallel: bool,
    },
    /// Run CI quality gates (format, lint, build, test).
    #[command(name = "ci")]
    Ci {
        /// Quick mode: skip long-running E2E gates.
        #[arg(long, short = 'q')]
        quick: bool,
        /// Write JSON report to this path.
        #[arg(long, short = 'r')]
        report: Option<std::path::PathBuf>,
        /// Output format: table, json, or toon (default: auto-detect).
        #[arg(long, value_parser)]
        format: Option<output::CliOutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long)]
        json: bool,
        /// Run independent gates in parallel (faster execution).
        #[arg(long, short = 'p')]
        parallel: bool,
    },
    /// Run a standard verification lane through build-slot admission and rch.
    #[command(name = "verify")]
    Verify(VerifyArgs),
    /// Release readiness evidence and operator verdicts.
    #[command(name = "release")]
    Release {
        #[command(subcommand)]
        action: ReleaseCommand,
    },
    /// Run native CLI benchmarks.
    #[command(name = "bench")]
    Bench {
        /// Quick mode: warmup=1, runs=3 unless overridden.
        #[arg(long, short = 'q')]
        quick: bool,
        /// Output format: table, json, or toon (default: auto-detect).
        #[arg(long, value_parser)]
        format: Option<output::CliOutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long, default_value_t = false)]
        json: bool,
        /// Path to baseline JSON for regression comparison.
        #[arg(long)]
        baseline: Option<PathBuf>,
        /// Persist current benchmark p95 values as a baseline JSON file.
        #[arg(long = "save-baseline")]
        save_baseline: Option<PathBuf>,
        /// Glob pattern to select benchmark names (example: "mail_*").
        #[arg(long)]
        filter: Option<String>,
        /// List selected benchmarks without executing them.
        #[arg(long, default_value_t = false)]
        list: bool,
        /// Override warmup iterations.
        #[arg(long)]
        warmup: Option<u32>,
        /// Override measured iterations.
        #[arg(long)]
        runs: Option<u32>,
    },
    /// Run clippy lints across the workspace (`cargo clippy --all-targets -D warnings`).
    Lint,
    /// Type-check the workspace without building binaries (`cargo check --all-targets`).
    Typecheck,
    /// Run E2E test suites.
    #[command(name = "e2e")]
    E2e {
        #[command(subcommand)]
        action: E2eCommand,
    },
    /// Create, inspect, and import encrypted shareable mailbox bundles.
    #[command(name = "share")]
    Share {
        #[command(subcommand)]
        action: ShareCommand,
    },
    /// Inspect and maintain the Git-backed message/reservation archive.
    #[command(name = "archive")]
    Archive {
        #[command(subcommand)]
        action: ArchiveCommand,
    },
    /// Install, check, and manage the pre-commit file-reservation guard hook.
    #[command(name = "guard")]
    Guard {
        #[command(subcommand)]
        action: GuardCommand,
    },
    /// Reserve, renew, release, and inspect file reservations.
    #[command(name = "file_reservations")]
    FileReservations {
        #[command(subcommand)]
        action: FileReservationsCommand,
    },
    /// List and send reminders for pending or overdue message acknowledgements.
    #[command(name = "acks")]
    Acks {
        #[command(subcommand)]
        action: AcksCommand,
    },
    /// List acknowledgement status for an agent's recent messages.
    #[command(name = "list-acks")]
    ListAcks {
        #[arg(long = "project")]
        project_key: String,
        #[arg(long = "agent")]
        agent_name: String,
        #[arg(long, default_value_t = 20)]
        limit: i64,
    },
    /// Migrate or check the on-disk database format (with backup/rollback).
    #[command(name = "migrate")]
    Migrate {
        /// Only check the database format without modifying anything.
        #[arg(long, default_value_t = false)]
        check: bool,
        /// Restore the database from the latest available backup and exit.
        #[arg(long, default_value_t = false)]
        rollback: bool,
        /// Force migration even if the format is unclear or mixed.
        #[arg(long, default_value_t = false)]
        force: bool,
        /// Custom backup directory (default: same directory as the database).
        #[arg(long)]
        backup_dir: Option<PathBuf>,
    },
    /// List registered projects (optionally including their agents).
    #[command(name = "list-projects")]
    ListProjects {
        #[arg(long, default_value_t = false)]
        include_agents: bool,
        /// Output format: table, json, or toon (default: auto-detect).
        #[arg(long, value_parser)]
        format: Option<output::CliOutputFormat>,
        /// Output JSON (shorthand for --format json).
        #[arg(long, default_value_t = false)]
        json: bool,
    },
    /// Destructively wipe all Agent Mail state (optionally archiving first).
    #[command(name = "clear-and-reset-everything")]
    ClearAndResetEverything {
        #[arg(
            long,
            short = 'f',
            help = "Skip the final destructive confirmation prompt (still asks about creating an archive)."
        )]
        force: bool,
        #[arg(
            long,
            conflicts_with = "no_archive",
            help = "Attempt a pre-reset archive before deleting data (default: prompt when interactive)."
        )]
        archive: bool,
        #[arg(
            long = "no-archive",
            conflicts_with = "archive",
            help = "Skip creating a pre-reset archive."
        )]
        no_archive: bool,
    },
    /// Inspect and edit Agent Mail configuration.
    #[command(name = "config")]
    Config {
        #[command(subcommand)]
        action: ConfigCommand,
    },
    /// Low-level control-plane utilities (build-slot environment inspection).
    #[command(name = "amctl")]
    Amctl {
        #[command(subcommand)]
        action: AmctlCommand,
    },
    /// Run a command while holding a build-slot file reservation.
    #[command(name = "am-run")]
    AmRun(AmRunArgs),
    /// Manage projects: register, adopt, mark identity, and discovery.
    #[command(name = "projects")]
    Projects {
        #[command(subcommand)]
        action: ProjectsCommand,
    },
    /// Send, read, search, reply to, and replay mailbox messages.
    #[command(name = "mail")]
    Mail {
        #[command(subcommand)]
        action: MailCommand,
    },
    /// Manage product records and link them to projects.
    #[command(name = "products")]
    Products {
        #[command(subcommand)]
        action: ProductsCommand,
    },
    /// Generate and insert Agent Mail documentation blurbs.
    #[command(name = "docs")]
    Docs {
        #[command(subcommand)]
        action: DocsCommand,
    },
    /// Diagnose and repair mailbox, archive, and database health.
    #[command(name = "doctor")]
    Doctor {
        #[command(subcommand)]
        action: DoctorCommand,
    },
    /// Register, list, and inspect agent identities.
    #[command(name = "agents")]
    Agents {
        #[command(subcommand)]
        action: AgentsCommand,
    },
    /// Inspect the MCP tool directory, schemas, and call metrics.
    #[command(name = "tooling")]
    Tooling {
        #[command(subcommand)]
        action: ToolingCommand,
    },
    /// Composite workflow macros (session boot, thread prep, reservation cycles, contact handshake).
    #[command(name = "macros")]
    Macros {
        #[command(subcommand)]
        action: MacroCommand,
    },
    /// Contact request/approve/reject/policy lifecycle.
    #[command(name = "contacts")]
    Contacts {
        #[command(subcommand)]
        action: ContactsCommand,
    },
    /// Query beads (issue tracker) status for the current project.
    #[command(name = "beads")]
    Beads {
        #[command(subcommand)]
        action: BeadsCommand,
    },
    /// Detect coding agents and configure MCP server connections.
    #[command(name = "setup")]
    Setup {
        #[command(subcommand)]
        action: SetupCommand,
    },
    /// Capture, verify, and inspect deterministic golden CLI artifacts.
    #[command(name = "golden")]
    Golden {
        #[command(subcommand)]
        action: GoldenCommand,
    },
    /// Flake triage: scan artifacts, reproduce failures, detect flaky tests.
    #[command(name = "flake-triage")]
    FlakeTriage {
        #[command(subcommand)]
        action: FlakeTriageCommand,
    },
    /// ATC maintenance and backfill workflows.
    #[command(name = "atc")]
    Atc {
        #[command(subcommand)]
        action: AtcCommand,
    },
    /// Agent-optimized commands with TOON/JSON/Markdown output.
    #[command(name = "robot")]
    Robot(robot::RobotArgs),
    /// Agent-targeted CLI docs and copy-paste workflow recipes.
    #[command(name = "robot-docs")]
    RobotDocs {
        #[command(subcommand)]
        action: RobotDocsCommand,
    },
    /// Legacy Python installation detection, migration/import, and status.
    #[command(name = "legacy")]
    Legacy(legacy::LegacyArgs),
    /// Upgrade helper: detect legacy install, import data, refresh setup.
    #[command(name = "upgrade")]
    Upgrade(legacy::UpgradeArgs),
    /// Check for updates or self-update the binary.
    ///
    /// Accepts both `am self-update` (legacy form) and `am update` (short
    /// alias matching `ntm update` / `caam update` conventions). Both
    /// dispatch to the same handler with identical flags.
    #[command(name = "self-update", alias = "update")]
    SelfUpdate {
        /// Only check for updates without installing.
        #[arg(long, default_value_t = false)]
        check: bool,
        /// Reinstall the current version (force re-download).
        #[arg(long, default_value_t = false)]
        force: bool,
        /// Install a specific version instead of the latest.
        #[arg(long)]
        version: Option<String>,
    },
    /// Cross-platform service management (systemd on Linux, launchd on macOS).
    #[command(name = "service")]
    Service {
        #[command(subcommand)]
        action: ServiceCommand,
    },
}

