/// Decide whether `check-inbox` should route through the daemon (HTTP) or read
/// SQLite directly.
///
/// The default (non-`--direct`) path always prefers the daemon. `--direct` prefers
/// the daemon only when it is reachable, falling back to a direct SQLite read when
/// no daemon is listening — this avoids contending on the WAL with a running
/// `serve-http` daemon's long-lived writer (GH#158).
const fn check_inbox_should_use_daemon(direct: bool, daemon_reachable: bool) -> bool {
    !direct || daemon_reachable
}

/// Handle the check-inbox command.
///
/// Checks the agent inbox for unread messages. Designed for git hooks and editor integrations.
/// Exits silently on any error (fail-safe for hooks - never interrupt agent work).
#[allow(clippy::too_many_arguments)]
fn handle_check_inbox(
    agent: Option<String>,
    rate_limit: u64,
    direct: bool,
    format: Option<output::CliOutputFormat>,
    json: bool,
    host: String,
    port: u16,
    project: Option<String>,
) -> CliResult<()> {
    let fmt = output::CliOutputFormat::resolve(format, json);

    // Resolve agent name from flag or environment variables
    let agent_name = agent
        .or_else(|| std::env::var("AGENT_NAME").ok())
        .or_else(|| std::env::var("AGENT_MAIL_AGENT").ok());

    let Some(agent_name) = agent_name else {
        // No agent configured - exit silently (not an error for hooks)
        return Ok(());
    };

    // Check for template/placeholder values (exit silently if detected)
    if value_looks_like_template(&agent_name) {
        return Ok(());
    }

    // Resolve project key from flag or environment
    let project_key = project
        .or_else(|| std::env::var("AGENT_MAIL_PROJECT").ok())
        .unwrap_or_else(|| {
            std::env::current_dir()
                .map(|p| p.to_string_lossy().replace('\\', "/"))
                .unwrap_or_default()
        });

    if value_looks_like_template(&project_key) {
        return Ok(());
    }

    // Apply rate limiting (unless disabled with rate_limit=0)
    if rate_limit > 0 {
        let limiter = CheckInboxRateLimiter::new(&agent_name, &project_key, Some(rate_limit));
        if !limiter.should_check() {
            // Rate limited - exit silently
            return Ok(());
        }
    }

    // Fetch inbox.
    //
    // `--direct` historically opened SQLite unconditionally, which contends on the
    // WAL with a running `serve-http` daemon's long-lived writer (GH#158). Prefer
    // the daemon over HTTP whenever it is reachable — even under `--direct` — and
    // fall back to a direct SQLite read only when no daemon is listening.
    let daemon_reachable = direct && process_owner_port_reachable(&host, port);
    let use_daemon = check_inbox_should_use_daemon(direct, daemon_reachable);

    let result = if use_daemon {
        // Build HTTP config and fetch via JSON-RPC.
        let config = Config::from_env();
        let config = resolve_check_inbox_rpc_config_reader(
            |key| std::env::var(key).ok(),
            &project_key,
            &agent_name,
            &host,
            port,
            &config.http_path,
        );
        let server_urls = config.server_urls.clone();

        // Use a minimal runtime for the async HTTP call
        let rt = asupersync::runtime::RuntimeBuilder::current_thread()
            .build()
            .map_err(|e| CliError::Other(format!("runtime error: {e}")))?;

        let via_daemon = rt
            .block_on(async { fetch_inbox_via_jsonrpc_with_fallback(&config, &server_urls).await });

        if direct && via_daemon.is_err() {
            // The daemon went away between the reachability probe and the call.
            // Honor the co-located `--direct` intent with a direct SQLite read.
            let config = CheckInboxDirectConfig {
                project_key,
                agent_name: agent_name.clone(),
                limit: CHECK_INBOX_FETCH_LIMIT,
            };
            check_inbox_direct(&config)
        } else {
            via_daemon
        }
    } else {
        // No daemon is listening — read SQLite directly (the fast co-located path).
        let config = CheckInboxDirectConfig {
            project_key,
            agent_name: agent_name.clone(),
            limit: CHECK_INBOX_FETCH_LIMIT,
        };
        check_inbox_direct(&config)
    };

    // Handle result - exit silently on any error (fail-safe for hooks)
    let result = match result {
        Ok(r) => r,
        Err(_) => return Ok(()), // Fail silently
    };

    // No messages - exit silently
    if result.unread_count == 0 {
        return Ok(());
    }

    // Build output data for JSON/TOON
    let output_data = serde_json::json!({
        "agent": agent_name,
        "unread_count": result.unread_count,
        "urgent_or_high_count": result.urgent_or_high_count,
        "messages": result.messages.iter().map(|m| {
            serde_json::json!({
                "id": m.id,
                "subject": m.subject,
                "from": m.from,
                "importance": m.importance,
                "created_ts": m.created_ts,
            })
        }).collect::<Vec<_>>(),
    });

    output::emit_output(&output_data, fmt, || {
        // Human-readable output with emoji
        ftui_runtime::ftui_println!();
        ftui_runtime::ftui_println!("📬 === INBOX REMINDER ===");
        if result.urgent_or_high_count > 0 {
            ftui_runtime::ftui_println!(
                "⚠️  You have {} message(s) in your inbox ({} urgent/high priority)",
                result.unread_count,
                result.urgent_or_high_count
            );
            ftui_runtime::ftui_println!("   Use fetch_inbox to check your messages!");
        } else {
            ftui_runtime::ftui_println!(
                "   You have {} recent message(s) in your inbox.",
                result.unread_count
            );
            ftui_runtime::ftui_println!(
                "   Consider checking with fetch_inbox if you haven't lately."
            );
        }
        ftui_runtime::ftui_println!("=========================");
        ftui_runtime::ftui_println!();
    });

    Ok(())
}

fn normalize_http_path(raw: &str) -> String {
    let trimmed = raw.trim();
    let lower = trimmed.to_ascii_lowercase();
    match lower.as_str() {
        "mcp" | "/mcp" | "/mcp/" => return "/mcp/".to_string(),
        "api" | "/api" | "/api/" => return "/api/".to_string(),
        _ => {}
    }

    if trimmed.is_empty() {
        return "/".to_string();
    }

    let mut with_leading = trimmed.to_string();
    if !with_leading.starts_with('/') {
        with_leading.insert(0, '/');
    }

    let without_trailing = with_leading.trim_end_matches('/');
    if without_trailing.is_empty() {
        "/".to_string()
    } else {
        format!("{without_trailing}/")
    }
}

fn check_inbox_server_url(host: &str, port: u16, http_path: &str) -> String {
    check_inbox_server_urls(host, port, http_path)
        .into_iter()
        .next()
        .unwrap_or_else(|| format!("http://{host}:{port}/"))
}

fn normalize_connect_host_for_client_url(host: &str) -> std::borrow::Cow<'_, str> {
    let trimmed = host.trim();
    if trimmed.is_empty() {
        return std::borrow::Cow::Borrowed("127.0.0.1");
    }

    let unbracketed = trimmed
        .strip_prefix('[')
        .and_then(|value| value.strip_suffix(']'))
        .unwrap_or(trimmed);

    match unbracketed {
        "0.0.0.0" => std::borrow::Cow::Borrowed("127.0.0.1"),
        "::" => std::borrow::Cow::Borrowed("[::1]"),
        _ => {
            if unbracketed.contains(':') && !trimmed.starts_with('[') {
                std::borrow::Cow::Owned(format!("[{unbracketed}]"))
            } else {
                std::borrow::Cow::Borrowed(trimmed)
            }
        }
    }
}

fn local_server_url_from_parts(host: &str, port: u16, http_path: &str) -> String {
    let connect_host = normalize_connect_host_for_client_url(host);
    format!("http://{connect_host}:{port}{http_path}")
}

pub(crate) fn local_server_bearer_token(config: &mcp_agent_mail_core::Config) -> Option<String> {
    config
        .http_bearer_token
        .clone()
        .or_else(managed_service_bearer_token)
}

fn mcp_base_alias_path(path: &str) -> Option<&'static str> {
    match path {
        "/api/" => Some("/mcp/"),
        "/mcp/" => Some("/api/"),
        _ => None,
    }
}

pub(crate) fn check_inbox_server_urls(host: &str, port: u16, http_path: &str) -> Vec<String> {
    let primary_path = normalize_http_path(http_path);
    let connect_host = normalize_connect_host_for_client_url(host);
    let mut urls = vec![format!("http://{connect_host}:{port}{primary_path}")];
    if let Some(alias_path) = mcp_base_alias_path(&primary_path) {
        let alias_url = format!("http://{connect_host}:{port}{alias_path}");
        if alias_url != urls[0] {
            urls.push(alias_url);
        }
    }
    urls
}

fn build_http_config(
    host: Option<String>,
    port: Option<u16>,
    path: Option<String>,
    no_auth: bool,
    allowed_host: Vec<String>,
) -> Config {
    let config = Config::from_env();
    apply_http_config_overrides(config, host, port, path, no_auth, allowed_host)
}

fn apply_http_config_overrides(
    mut config: Config,
    host: Option<String>,
    port: Option<u16>,
    path: Option<String>,
    no_auth: bool,
    allowed_host: Vec<String>,
) -> Config {
    // Keep env and CLI semantics aligned (`HTTP_PATH=mcp` == `--path mcp`).
    config.http_path = normalize_http_path(&config.http_path);
    if let Some(host) = host {
        config.http_host = host;
    }
    if let Some(port) = port {
        config.http_port = port;
    }
    if let Some(path) = path {
        config.http_path = normalize_http_path(&path);
    }
    // Merge `--allowed-host` flags with any HTTP_ALLOWED_HOSTS env values so the
    // listener accepts these Host headers in addition to the loopback built-ins.
    // CLI and env compose (neither clobbers the other); duplicates are deduped
    // later in the server's `http_allowed_hosts`. See GitHub issue #146.
    for extra in allowed_host {
        let trimmed = extra.trim();
        if !trimmed.is_empty()
            && !config
                .http_allowed_hosts
                .iter()
                .any(|existing| existing == trimmed)
        {
            config.http_allowed_hosts.push(trimmed.to_string());
        }
    }
    if no_auth {
        // Disable bearer token authentication for this run. `--no-auth` is the
        // documented "for local development" contract: no auth required for ANY
        // operation, reads and writes alike. Clearing the bearer token only
        // disables the bearer/JWT gate; the RBAC layer (enabled by default with
        // a read-only `reader` default role) still 403s every write tool unless
        // the request is classified `is_local_ok`. Since 89b8a3e0 flipped the
        // `http_allow_localhost_unauthenticated` default from true to false,
        // localhost requests stopped being `is_local_ok`, so `--no-auth` writes
        // started returning 403 (regression first shipped in v0.3.0, breaking
        // every ntm-spawned `am serve-http --no-auth` session). Re-enabling the
        // localhost-unauthenticated bypass for this run restores the v0.2.x
        // contract without weakening the default posture for authenticated
        // serve-http runs. `allow_local_unauthenticated` still requires an
        // actual local peer address and rejects forwarded headers, so remote
        // callers remain unauthenticated-denied even under `--no-auth`.
        // See: https://github.com/Dicklesworthstone/mcp_agent_mail_rust/issues/131
        config.http_bearer_token = None;
        config.http_allow_localhost_unauthenticated = true;
        eprintln!("[info] --no-auth: Bearer token authentication disabled for this run");
    }
    config
}

fn handle_doctor(action: DoctorCommand) -> CliResult<()> {
    match action {
        DoctorCommand::Check {
            project,
            verbose,
            format,
            json,
        } => handle_doctor_check(project, verbose, format, json),
        DoctorCommand::Repair {
            project,
            dry_run,
            yes,
            backup_dir,
            prune_orphan_recipients,
            allow_live_owner,
        } => handle_doctor_repair(
            project,
            dry_run,
            yes,
            backup_dir,
            prune_orphan_recipients,
            allow_live_owner,
        ),
        DoctorCommand::Backups { format, json } => handle_doctor_backups(format, json),
        DoctorCommand::Restore {
            backup_path,
            dry_run,
            yes,
        } => handle_doctor_restore(backup_path, dry_run, yes),
        DoctorCommand::Reconstruct {
            dry_run,
            yes,
            json,
            allow_live_owner,
        } => handle_doctor_reconstruct(dry_run, yes, json, allow_live_owner),
        DoctorCommand::Drain { format, json } => handle_doctor_drain(format, json),
        DoctorCommand::ArchiveScan { format, json } => handle_doctor_archive_scan(format, json),
        DoctorCommand::ArchiveVerify { format, json } => handle_doctor_archive_verify(format, json),
        DoctorCommand::ArchiveNormalize {
            dry_run,
            yes,
            json,
            apply_mode,
            prune_released_reservations,
            reservation_retention_days,
        } => handle_doctor_archive_normalize(
            dry_run,
            yes,
            json,
            apply_mode,
            prune_released_reservations,
            reservation_retention_days,
        ),
        DoctorCommand::Fix {
            dry_run,
            yes,
            json,
            only,
            list,
        } => {
            if let Some(fm_id) = only {
                if list {
                    doctor::handle_fix_only_list(&fm_id, json)
                } else {
                    doctor::handle_fix_only(&fm_id, dry_run, yes, json)
                }
            } else if list {
                // Pass-24: `--list` without `--only` enumerates every
                // registered FM in one round-trip. Replaces the
                // pass-16 exit-2 reject path with a real verb.
                doctor::handle_fix_list_all(json)
            } else {
                handle_doctor_fix(dry_run, yes, json)
            }
        }
        DoctorCommand::FixOrphanRefs {
            project,
            all,
            apply,
            force,
            format,
        } => handle_doctor_fix_orphan_refs(project, all, apply, force, format),
        DoctorCommand::PackArchive { plan, json } => handle_doctor_pack_archive(plan, json),
        DoctorCommand::Artifacts {
            format,
            json,
            largest,
        } => handle_doctor_artifacts(format, json, largest),
        DoctorCommand::Reclaim {
            dry_run,
            yes,
            keep,
            max_age_days,
            json,
        } => handle_doctor_reclaim(dry_run, yes, keep, max_age_days, json),
        DoctorCommand::SupportBundle {
            output_dir,
            stdout_log,
            stderr_log,
            redact_subjects,
            format,
            json,
        } => doctor::handle_support_bundle(
            output_dir,
            stdout_log,
            stderr_log,
            redact_subjects,
            format,
            json,
        ),
        DoctorCommand::Capabilities { format } => doctor::handle_capabilities(format),
        DoctorCommand::RobotDocs => doctor::handle_robot_docs(),
        DoctorCommand::Undo {
            run_id,
            dry_run,
            strict,
            format,
        } => {
            let target = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
            doctor::handle_undo(&target, &run_id, dry_run, strict, format)
        }
        DoctorCommand::Ls { format } => {
            let target = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
            doctor::handle_ls(&target, format)
        }
        DoctorCommand::Health => {
            let target = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
            doctor::handle_health(&target)
        }
        DoctorCommand::Locks { format, json } => handle_doctor_locks(format, json),
        DoctorCommand::Triage { quick } => {
            let target = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
            doctor::handle_triage(&target, quick)
        }
        DoctorCommand::Explain { finding_id, format } => {
            let target = std::env::current_dir().unwrap_or_else(|_| std::path::PathBuf::from("."));
            doctor::handle_explain(&target, &finding_id, format)
        }
        DoctorCommand::Selftest { format } => doctor::handle_selftest(format),
        DoctorCommand::WriteSelftest { format } => doctor::selftest::handle_write_selftest(format),
        DoctorCommand::McpSelftest { format } => doctor::selftest::handle_mcp_selftest(format),
        DoctorCommand::Fixers { format } => doctor::handle_fixers(format),
    }
}

fn handle_doctor_pack_archive(plan_only: bool, json: bool) -> CliResult<()> {
    let config = mcp_agent_mail_core::Config::from_env();
    let git_dir =
        mcp_agent_mail_server::maintenance::resolve_archive_git_dir(&config).ok_or_else(|| {
            CliError::Other(format!(
                "could not locate archive .git directory under {}",
                config.storage_root.display()
            ))
        })?;

    let plan = mcp_agent_mail_server::maintenance::plan_archive_maintenance(
        &config.storage_root,
        &git_dir,
    );
    if plan_only {
        if json {
            println!(
                "{}",
                serde_json::to_string_pretty(&plan).unwrap_or_default()
            );
        } else {
            render_archive_maintenance_plan(&plan);
        }
        return Ok(());
    }

    let report = mcp_agent_mail_server::maintenance::run_maintenance(&git_dir);

    if json {
        let obj = serde_json::json!({
            "success": report.success,
            "git_dir": git_dir.display().to_string(),
            "loose_before": report.loose_before,
            "loose_after": report.loose_after,
            "pack_count_before": report.pack_count_before,
            "pack_count_after": report.pack_count_after,
            "disk_bytes_before": report.disk_bytes_before,
            "disk_bytes_after": report.disk_bytes_after,
            "error": report.error,
            "plan_before": plan,
        });
        println!("{}", serde_json::to_string_pretty(&obj).unwrap_or_default());
    } else {
        if let Some(err) = &report.error {
            eprintln!("ERROR: {err}");
        }
        println!(
            "Archive maintenance: {}",
            if report.success { "OK" } else { "FAILED" }
        );
        println!();
        println!("  {:>20}  {:>10}  {:>10}", "", "Before", "After");
        println!(
            "  {:>20}  {:>10}  {:>10}",
            "Loose objects",
            report
                .loose_before
                .map_or("-".to_string(), |v| v.to_string()),
            report
                .loose_after
                .map_or("-".to_string(), |v| v.to_string()),
        );
        println!(
            "  {:>20}  {:>10}  {:>10}",
            "Pack files",
            report
                .pack_count_before
                .map_or("-".to_string(), |v| v.to_string()),
            report
                .pack_count_after
                .map_or("-".to_string(), |v| v.to_string()),
        );
        let fmt_bytes = |b: Option<u64>| -> String {
            match b {
                Some(bytes) if bytes >= 1024 * 1024 => {
                    format!("{:.1} MB", bytes as f64 / (1024.0 * 1024.0))
                }
                Some(bytes) if bytes >= 1024 => format!("{:.1} KB", bytes as f64 / 1024.0),
                Some(bytes) => format!("{bytes} B"),
                None => "-".to_string(),
            }
        };
        println!(
            "  {:>20}  {:>10}  {:>10}",
            "Disk usage",
            fmt_bytes(report.disk_bytes_before),
            fmt_bytes(report.disk_bytes_after),
        );
        if let (Some(before), Some(after)) = (report.disk_bytes_before, report.disk_bytes_after) {
            let reclaimed = before.saturating_sub(after);
            if reclaimed > 0 {
                println!();
                println!("  Reclaimed: {}", fmt_bytes(Some(reclaimed)));
            }
        }
    }

    if report.success {
        Ok(())
    } else {
        Err(CliError::Other("maintenance failed".into()))
    }
}

fn render_archive_maintenance_plan(
    plan: &mcp_agent_mail_server::maintenance::ArchiveMaintenancePlan,
) {
    output::section("Archive Pack Plan:");
    output::kv("Storage root", &plan.storage_root);
    output::kv("Git dir", &plan.git_dir);
    output::kv("Verdict", &format!("{:?}", plan.verdict));
    output::kv("Global archive", &format_bytes(plan.global_archive_bytes));
    output::kv(
        "Git objects",
        &plan
            .git_objects_bytes
            .map_or_else(|| "-".to_string(), format_bytes),
    );
    output::kv(
        "Loose objects",
        &plan
            .loose_objects
            .map_or_else(|| "-".to_string(), |value| value.to_string()),
    );
    output::kv(
        "Pack files",
        &plan
            .pack_file_count
            .map_or_else(|| "-".to_string(), |value| value.to_string()),
    );
    output::kv("Pack bytes", &format_bytes(plan.pack_file_bytes));

    ftui_runtime::ftui_println!("");
    output::section("  Thresholds:");
    let mut thresholds =
        output::CliTable::new(vec!["METRIC", "VALUE", "WATCH", "CRITICAL", "VERDICT"]);
    for threshold in &plan.threshold_verdicts {
        thresholds.add_row(vec![
            threshold.metric.clone(),
            threshold
                .value
                .map_or_else(|| "-".to_string(), |value| value.to_string()),
            threshold.watch_at.to_string(),
            threshold.critical_at.to_string(),
            format!("{:?}", threshold.verdict),
        ]);
    }
    thresholds.render();

    ftui_runtime::ftui_println!("");
    output::section("  Largest Projects:");
    if plan.project_sizes.is_empty() {
        output::emit_empty(
            output::CliOutputFormat::Table,
            "No project archives were found.",
        );
    } else {
        let mut table = output::CliTable::new(vec!["PROJECT", "SIZE", "FILES"]);
        for project in plan.project_sizes.iter().take(8) {
            table.add_row(vec![
                project.project_slug.clone(),
                format_bytes(project.bytes),
                project.files.to_string(),
            ]);
        }
        table.render();
    }

    ftui_runtime::ftui_println!("");
    output::section("  Top Artifact Categories:");
    if plan.top_artifact_categories.is_empty() {
        output::emit_empty(
            output::CliOutputFormat::Table,
            "No artifact categories were found.",
        );
    } else {
        let mut table = output::CliTable::new(vec!["CATEGORY", "SIZE", "FILES"]);
        for category in &plan.top_artifact_categories {
            table.add_row(vec![
                category.category.clone(),
                format_bytes(category.bytes),
                category.files.to_string(),
            ]);
        }
        table.render();
    }

    ftui_runtime::ftui_println!("");
    output::section("  Safe Commands:");
    for command in &plan.safe_commands {
        let mode = if command.mutates_archive {
            "stateful"
        } else {
            "read-only"
        };
        ftui_runtime::ftui_println!("  - {mode}: {}", command.command);
        ftui_runtime::ftui_println!("    {}", command.purpose);
    }
}

fn handle_doctor_artifacts(
    format: Option<output::CliOutputFormat>,
    json_mode: bool,
    largest: usize,
) -> CliResult<()> {
    let fmt = output::CliOutputFormat::resolve(format, json_mode);
    let config = Config::from_env();
    let repo_root = std::env::current_dir()?;
    let report =
        mcp_agent_mail_server::retention::artifact_retention_report(&config, &repo_root, largest);

    output::emit_output(&report, fmt, || {
        output::section("Artifact Retention Report:");
        output::kv("Repository", &report.repo_root);
        output::kv("Storage root", &report.storage_root);
        output::kv(
            "Roots",
            &format!(
                "{} existing / {} reported",
                report.totals.roots_existing, report.totals.roots_reported
            ),
        );
        output::kv("Total size", &format_bytes(report.totals.total_bytes));
        output::kv("Total files", &report.totals.total_files.to_string());
        output::kv("Disk pressure", &report.disk.pressure);
        if let Some(free_bytes) = report.disk.effective_free_bytes {
            output::kv("Effective free", &format_bytes(free_bytes));
        }

        ftui_runtime::ftui_println!("");
        output::section("  Largest Roots:");
        if report.largest_roots.is_empty() {
            output::emit_empty(fmt, "No artifact roots with files were found.");
        } else {
            let mut table = output::CliTable::new(vec!["ROOT", "CLASS", "SIZE", "FILES", "PATH"]);
            for root in &report.largest_roots {
                table.add_row(vec![
                    root.name.clone(),
                    root.retention_class.clone(),
                    format_bytes(root.bytes),
                    root.files.to_string(),
                    root.path.clone(),
                ]);
            }
            table.render();
        }

        if !report.warnings.is_empty() {
            ftui_runtime::ftui_println!("");
            output::section("  Warnings:");
            for warning in &report.warnings {
                output::warn(&format!(
                    "[{}] {}: {}",
                    warning.severity, warning.code, warning.detail
                ));
                for root in &warning.largest_roots {
                    ftui_runtime::ftui_println!(
                        "    largest_root={} bytes={} path={}",
                        root.name,
                        root.bytes,
                        root.path
                    );
                }
                ftui_runtime::ftui_println!("    remediation={}", warning.safe_remediation);
            }
        }

        ftui_runtime::ftui_println!("");
        output::section("  Safety:");
        for remediation in &report.safe_remediation {
            ftui_runtime::ftui_println!("  - {remediation}");
        }
    });
    Ok(())
}

#[derive(serde::Serialize)]
struct DoctorReclaimArtifact {
    path: String,
    category: String,
    bytes: u64,
    modified_us: i64,
}

#[derive(serde::Serialize)]
struct DoctorReclaimReport {
    storage_root: String,
    database: String,
    keep_min: u64,
    max_age_days: u64,
    applied: bool,
    total_artifacts: usize,
    total_bytes: u64,
    reclaimable_artifacts: usize,
    reclaimable_bytes: u64,
    kept_artifacts: usize,
    reclaimable: Vec<DoctorReclaimArtifact>,
    #[serde(skip_serializing_if = "Option::is_none")]
    moved_to: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    moved: Option<usize>,
    #[serde(skip_serializing_if = "Option::is_none")]
    moved_bytes: Option<u64>,
    failures: Vec<String>,
    note: String,
}

/// `am doctor reclaim` — consolidate stale recovery debris (br-mudrv).
///
/// Read-only preview by default; `--yes` MOVES (never deletes) the stale
/// forensic bundles + corrupt-DB quarantines into one reversible
/// `<storage_root>/doctor/reclaimable/<ts>/` directory the operator can remove.
fn handle_doctor_reclaim(
    dry_run: bool,
    yes: bool,
    keep: Option<u64>,
    max_age_days: Option<u64>,
    json_mode: bool,
) -> CliResult<()> {
    use mcp_agent_mail_db::recovery_retention as rr;
    let fmt = output::CliOutputFormat::resolve(None, json_mode);
    let config = Config::from_env();
    let pool_cfg = mcp_agent_mail_db::DbPoolConfig::from_env();
    let configured_path = pool_cfg
        .sqlite_path()
        .map_err(|e| CliError::Other(format!("bad database URL: {e}")))?;
    if configured_path == ":memory:" {
        return Err(CliError::Other(
            "in-memory databases have no on-disk recovery debris to reclaim".to_string(),
        ));
    }
    let resolved = resolve_sqlite_path_with_absolute_candidate(&configured_path);
    let db_path = PathBuf::from(&resolved);
    let storage_root = config.storage_root.clone();

    let keep_min = keep.unwrap_or(config.doctor_retention_keep_min);
    let max_age_secs = match max_age_days {
        Some(days) => days.saturating_mul(86_400),
        None => config.doctor_retention_max_age_secs,
    };

    let artifacts = rr::enumerate_recovery_debris(&storage_root, &db_path);
    let now_us = chrono::Utc::now().timestamp_micros();
    let plan = rr::select_recovery_debris_to_reclaim(
        artifacts,
        rr::RetentionPolicy {
            keep_min: usize::try_from(keep_min).unwrap_or(usize::MAX),
            max_age_secs,
        },
        now_us,
    );

    let apply = yes && !dry_run;
    let mut moved_to = None;
    let mut moved = None;
    let mut moved_bytes = None;
    let mut failures: Vec<String> = Vec::new();

    if apply && plan.has_reclaimable() {
        let ts = chrono::Utc::now().format("%Y%m%d_%H%M%S").to_string();
        let dest = storage_root.join("doctor").join("reclaimable").join(&ts);
        let outcome = rr::consolidate_debris(&plan, &dest)
            .map_err(|e| CliError::Other(format!("reclaim consolidation failed: {e}")))?;
        moved_to = Some(dest.display().to_string());
        moved = Some(outcome.moved);
        moved_bytes = Some(outcome.moved_bytes);
        failures = outcome
            .failures
            .iter()
            .map(|(p, e)| format!("{}: {e}", p.display()))
            .collect();
    }

    let note = if apply {
        format!(
            "Moved {} stale artifact(s) into a reclaimable directory (nothing was deleted). Remove that directory with `rm -rf` to free the disk.",
            moved.unwrap_or(0)
        )
    } else if plan.has_reclaimable() {
        "Preview only — re-run with --yes to consolidate the stale debris into doctor/reclaimable/ (nothing is ever deleted automatically).".to_string()
    } else {
        "No stale recovery debris beyond the retention policy.".to_string()
    };

    let report = DoctorReclaimReport {
        storage_root: storage_root.display().to_string(),
        database: resolved.clone(),
        keep_min,
        max_age_days: max_age_secs / 86_400,
        applied: apply,
        total_artifacts: plan.total_count,
        total_bytes: plan.total_bytes,
        reclaimable_artifacts: plan.prune.len(),
        reclaimable_bytes: plan.reclaimable_bytes,
        kept_artifacts: plan.kept_count,
        reclaimable: plan
            .prune
            .iter()
            .map(|a| DoctorReclaimArtifact {
                path: a.path.display().to_string(),
                category: a.category.as_str().to_string(),
                bytes: a.bytes,
                modified_us: a.modified_us,
            })
            .collect(),
        moved_to,
        moved,
        moved_bytes,
        failures: failures.clone(),
        note,
    };

    output::emit_output(&report, fmt, || {
        output::section("Doctor Recovery-Debris Reclaim:");
        output::kv("Storage root", &report.storage_root);
        output::kv("Database", &report.database);
        output::kv(
            "Policy",
            &format!(
                "keep >= {} newest per category, keep < {} days old",
                report.keep_min, report.max_age_days
            ),
        );
        output::kv(
            "Total debris",
            &format!(
                "{} artifact(s), {}",
                report.total_artifacts,
                format_bytes(report.total_bytes)
            ),
        );
        output::kv(
            "Reclaimable",
            &format!(
                "{} artifact(s), {}",
                report.reclaimable_artifacts,
                format_bytes(report.reclaimable_bytes)
            ),
        );
        output::kv("Kept", &report.kept_artifacts.to_string());
        if report.reclaimable.is_empty() {
            output::emit_empty(fmt, "No stale recovery debris beyond the retention policy.");
        } else {
            ftui_runtime::ftui_println!("");
            output::section("  Reclaimable (oldest first):");
            let mut table = output::CliTable::new(vec!["CATEGORY", "SIZE", "PATH"]);
            for a in &report.reclaimable {
                table.add_row(vec![
                    a.category.clone(),
                    format_bytes(a.bytes),
                    a.path.clone(),
                ]);
            }
            table.render();
        }
        if let Some(dest) = &report.moved_to {
            ftui_runtime::ftui_println!("");
            output::kv("Moved to", dest);
            output::kv(
                "Moved",
                &format!(
                    "{} artifact(s), {}",
                    report.moved.unwrap_or(0),
                    format_bytes(report.moved_bytes.unwrap_or(0))
                ),
            );
        }
        if !report.failures.is_empty() {
            ftui_runtime::ftui_println!("");
            output::section("  Failures:");
            for failure in &report.failures {
                output::warn(failure);
            }
        }
        ftui_runtime::ftui_println!("");
        ftui_runtime::ftui_println!("{}", report.note);
    });

    if !failures.is_empty() {
        return Err(CliError::ExitCode(1));
    }
    Ok(())
}

fn handle_guard(action: GuardCommand) -> CliResult<()> {
    match action {
        GuardCommand::Install {
            project,
            repo,
            prepush,
            no_prepush,
        } => {
            let install_prepush = if prepush { true } else { !no_prepush };
            mcp_agent_mail_guard::install_guard(&project, repo.as_path(), install_prepush)?;
            ftui_runtime::ftui_println!("Guard installed successfully.");
            Ok(())
        }
        GuardCommand::Uninstall { repo } => {
            mcp_agent_mail_guard::uninstall_guard(repo.as_path())?;
            ftui_runtime::ftui_println!("Guard uninstalled successfully.");
            Ok(())
        }
        GuardCommand::Status { repo } => {
            let status = mcp_agent_mail_guard::guard_status(&repo)?;
            output::section("Guard Status:");
            output::kv("Hooks dir", &status.hooks_dir);
            output::kv("Mode", &format!("{:?}", status.guard_mode));
            output::kv("Worktrees", &status.worktrees_enabled.to_string());
            output::kv(
                "Pre-commit",
                if status.pre_commit_present {
                    "installed"
                } else {
                    "not installed"
                },
            );
            output::kv(
                "Pre-push",
                if status.pre_push_present {
                    "installed"
                } else {
                    "not installed"
                },
            );
            Ok(())
        }
        GuardCommand::Check {
            stdin_nul,
            advisory,
            repo,
        } => {
            let repo_path = repo.unwrap_or_else(|| std::env::current_dir().unwrap_or_default());
            // Read paths from stdin (null-separated or line-separated)
            let input = {
                use std::io::Read;
                let mut buf = Vec::new();
                std::io::stdin()
                    .read_to_end(&mut buf)
                    .map_err(|e| CliError::Other(format!("Failed to read stdin: {e}")))?;
                String::from_utf8_lossy(&buf).into_owned()
            };
            let paths: Vec<String> = if stdin_nul {
                input
                    .split('\0')
                    .filter(|s| !s.is_empty())
                    .map(String::from)
                    .collect()
            } else {
                input
                    .lines()
                    .filter(|s| !s.is_empty())
                    .map(String::from)
                    .collect()
            };

            let config = mcp_agent_mail_core::Config::from_env();
            let archive_root = resolve_guard_archive_root_for_check(&repo_path, &config);

            let conflicts =
                mcp_agent_mail_guard::guard_check(&archive_root, &repo_path, &paths, advisory)?;
            if conflicts.is_empty() {
                ftui_runtime::ftui_println!("No file reservation conflicts detected.");
            } else {
                for c in &conflicts {
                    ftui_runtime::ftui_eprintln!(
                        "CONFLICT: pattern '{}' held by {} (expires {})",
                        c.pattern,
                        c.holder,
                        c.expires_ts
                    );
                }
                if !advisory {
                    return Err(CliError::ExitCode(1));
                }
            }
            Ok(())
        }
    }
}

fn path_is_real_directory(path: &Path) -> bool {
    std::fs::symlink_metadata(path).is_ok_and(|metadata| metadata.file_type().is_dir())
}

fn project_identity_matches_requested_path(
    stored_human_key: &str,
    requested_identity: &mcp_agent_mail_core::ProjectIdentity,
) -> bool {
    let stored_identity = resolve_project_identity(stored_human_key);
    stored_identity.human_key == requested_identity.human_key
        || stored_identity.canonical_path == requested_identity.canonical_path
}

fn archive_project_matches_repo_path(
    candidate: &Path,
    repo_identity: &mcp_agent_mail_core::ProjectIdentity,
) -> bool {
    let metadata_path = candidate.join("project.json");
    if !path_is_real_file(&metadata_path) {
        return false;
    }

    let Ok(content) = std::fs::read_to_string(&metadata_path) else {
        return false;
    };
    let Ok(metadata) = serde_json::from_str::<serde_json::Value>(&content) else {
        return false;
    };
    let Some(human_key) = metadata
        .get("human_key")
        .and_then(serde_json::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        return false;
    };

    project_identity_matches_requested_path(human_key, repo_identity)
}

fn resolve_guard_archive_root_for_check(repo_path: &Path, config: &Config) -> PathBuf {
    if path_is_real_directory(&repo_path.join("file_reservations")) {
        return repo_path.to_path_buf();
    }

    let projects_dir = config.storage_root.join("projects");
    if !path_is_real_directory(&projects_dir) {
        return repo_path.to_path_buf();
    }

    let human_key = repo_path.to_string_lossy().to_string();
    let identity = resolve_project_identity(&human_key);
    let candidate = projects_dir.join(&identity.slug);
    if path_is_real_directory(&candidate.join("file_reservations"))
        && archive_project_matches_repo_path(&candidate, &identity)
    {
        return candidate;
    }

    let Ok(entries) = std::fs::read_dir(&projects_dir) else {
        return repo_path.to_path_buf();
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path == candidate || !path_is_real_directory(&path.join("file_reservations")) {
            continue;
        }
        if archive_project_matches_repo_path(&path, &identity) {
            return path;
        }
    }

    repo_path.to_path_buf()
}

fn handle_list_projects(
    include_agents: bool,
    format: Option<output::CliOutputFormat>,
    json: bool,
) -> CliResult<()> {
    let cfg = mcp_agent_mail_db::DbPoolConfig::from_env();
    handle_list_projects_with_database_url(&cfg.database_url, include_agents, format, json)
}

fn handle_list_projects_with_database_url(
    database_url: &str,
    include_agents: bool,
    format: Option<output::CliOutputFormat>,
    json: bool,
) -> CliResult<()> {
    let fmt = output::CliOutputFormat::resolve(format, json);
    let config = Config::from_env();
    let opened = open_db_sync_canonical_read_with_database_url(
        database_url,
        Some(&config.storage_root),
        "list-projects",
    )?;
    let conn = opened.conn();

    let projects = conn
        .query_sync(
            "SELECT id, slug, human_key, created_at FROM projects ORDER BY id",
            &[],
        )
        .map_err(|e| CliError::Other(format!("query failed: {e}")))?;

    if projects.is_empty() {
        output::emit_empty(fmt, "No projects found.");
        return Ok(());
    }

    // Pre-fetch agents once if needed (avoids duplicate queries)
    let agents_by_project: std::collections::HashMap<i64, Vec<(String, String, String)>> =
        if include_agents {
            let mut map = std::collections::HashMap::new();
            for row in &projects {
                let id: i64 = row.get_named("id").unwrap_or(0);
                let agents = conn
                    .query_sync(
                        "SELECT name, program, model FROM agents WHERE project_id = ?",
                        &[sqlmodel_core::Value::BigInt(id)],
                    )
                    .unwrap_or_default();
                let agent_list: Vec<(String, String, String)> = agents
                    .iter()
                    .map(|a| {
                        let name: String = a.get_named("name").unwrap_or_default();
                        let program: String = a.get_named("program").unwrap_or_default();
                        let model: String = a.get_named("model").unwrap_or_default();
                        (name, program, model)
                    })
                    .collect();
                map.insert(id, agent_list);
            }
            map
        } else {
            std::collections::HashMap::new()
        };

    // Build serializable data structure for JSON/TOON output
    let mut output_data: Vec<serde_json::Value> = Vec::new();
    for row in &projects {
        let id: i64 = row.get_named("id").unwrap_or(0);
        let slug: String = row.get_named("slug").unwrap_or_default();
        let human_key: String = row.get_named("human_key").unwrap_or_default();
        let created_at: i64 = row.get_named("created_at").unwrap_or(0);

        let mut entry = serde_json::json!({
            "id": id,
            "slug": slug,
            "human_key": human_key,
            "created_at": mcp_agent_mail_db::timestamps::micros_to_iso(created_at),
        });

        if include_agents && let Some(agent_list) = agents_by_project.get(&id) {
            let agents_json: Vec<serde_json::Value> = agent_list
                .iter()
                .map(|(name, program, model)| {
                    serde_json::json!({ "name": name, "program": program, "model": model })
                })
                .collect();
            if let Some(obj) = entry.as_object_mut() {
                obj.insert("agents".to_string(), serde_json::json!(agents_json));
            }
        }
        output_data.push(entry);
    }

    output::emit_output(&output_data, fmt, || {
        // Table rendering
        let mut table = output::CliTable::new(vec!["ID", "SLUG", "HUMAN_KEY"]);
        for row in &projects {
            let id: i64 = row.get_named("id").unwrap_or(0);
            let slug: String = row.get_named("slug").unwrap_or_default();
            let human_key: String = row.get_named("human_key").unwrap_or_default();
            table.add_row(vec![id.to_string(), slug, human_key]);
        }
        table.render();
        if include_agents {
            ftui_runtime::ftui_println!("");
            for row in &projects {
                let id: i64 = row.get_named("id").unwrap_or(0);
                let slug: String = row.get_named("slug").unwrap_or_default();
                if let Some(agent_list) = agents_by_project.get(&id)
                    && !agent_list.is_empty()
                {
                    output::section(&format!("Agents for {slug}:"));
                    for (name, program, model) in agent_list {
                        ftui_runtime::ftui_println!("  {name} ({program}/{model})");
                    }
                }
            }
        }
    });
    Ok(())
}

fn is_sqlite_corruption_error_message(message: &str) -> bool {
    mcp_agent_mail_db::is_corruption_error_message(message)
}

fn is_sqlite_recovery_error_message(message: &str) -> bool {
    let lower = message.to_ascii_lowercase();
    is_sqlite_corruption_error_message(message)
        || lower.contains("out of memory")
        || lower.contains("cursor stack is empty")
        || lower.contains("called `option::unwrap()` on a `none` value")
        || lower.contains("internal error")
        || lower.contains("cursor must be on a leaf")
}

fn path_is_real_file(path: &Path) -> bool {
    std::fs::symlink_metadata(path).is_ok_and(|metadata| metadata.file_type().is_file())
}

fn path_is_occupied(path: &Path) -> bool {
    match std::fs::symlink_metadata(path) {
        Ok(_) => true,
        Err(err) => err.kind() != std::io::ErrorKind::NotFound,
    }
}

fn path_is_self_update_binary_file(path: &Path) -> bool {
    let Ok(metadata) = std::fs::symlink_metadata(path) else {
        return false;
    };
    if !metadata.file_type().is_file() {
        return false;
    }
    #[cfg(unix)]
    {
        use std::os::unix::fs::MetadataExt;
        if metadata.nlink() != 1 {
            return false;
        }
    }
    true
}

fn doctor_legacy_fts_tables_from_query<F>(mut query: F) -> Vec<String>
where
    F: FnMut(&str) -> Result<Vec<mcp_agent_mail_db::sqlmodel_core::Row>, String>,
{
    let mut names = query(
        "SELECT name \
         FROM sqlite_master \
         WHERE type='table' AND ( \
             name IN ('fts_messages', 'fts_agents', 'fts_projects', \
                      'messages_fts', 'agents_fts', 'projects_fts') \
             OR lower(COALESCE(sql, '')) LIKE '%using fts5%' \
         )",
    )
    .ok()
    .into_iter()
    .flatten()
    .filter_map(|row| row.get_named::<String>("name").ok())
    .collect::<Vec<_>>();
    names.sort();
    names.dedup();
    names
}

fn doctor_legacy_fts_tables(conn: &mcp_agent_mail_db::DbConn) -> Vec<String> {
    doctor_legacy_fts_tables_from_query(|sql| conn.query_sync(sql, &[]).map_err(|e| e.to_string()))
}

fn doctor_legacy_fts_tables_canonical(conn: &mcp_agent_mail_db::CanonicalDbConn) -> Vec<String> {
    doctor_legacy_fts_tables_from_query(|sql| conn.query_sync(sql, &[]).map_err(|e| e.to_string()))
}

fn guard_status_missing_repo(message: &str) -> bool {
    let lower = message.to_ascii_lowercase();
    lower.contains("could not find repository")
        || (lower.contains("repository") && lower.contains("notfound"))
}

fn sqlite_pragma_check_rows_ok(
    rows: &[mcp_agent_mail_db::sqlmodel_core::Row],
    kind: mcp_agent_mail_db::CheckKind,
) -> bool {
    let details = mcp_agent_mail_db::integrity::extract_check_details(rows, kind);
    mcp_agent_mail_db::integrity::details_indicate_ok(&details)
        || mcp_agent_mail_db::integrity::integrity_details_are_suspect(&details)
}

fn sqlite_query_check_rows<F>(
    mut query: F,
    kind: mcp_agent_mail_db::CheckKind,
) -> CliResult<Vec<mcp_agent_mail_db::sqlmodel_core::Row>>
where
    F: FnMut(&str) -> Result<Vec<mcp_agent_mail_db::sqlmodel_core::Row>, String>,
{
    mcp_agent_mail_db::integrity::probe_check_rows(|sql| query(sql), kind)
        .map_err(|error| CliError::Other(format!("PRAGMA {kind} failed: {error}")))
}

fn sqlite_conn_check_ok(
    conn: &mcp_agent_mail_db::DbConn,
    kind: mcp_agent_mail_db::CheckKind,
) -> CliResult<bool> {
    let rows = sqlite_query_check_rows(
        |sql| conn.query_sync(sql, &[]).map_err(|e| e.to_string()),
        kind,
    )?;
    Ok(sqlite_pragma_check_rows_ok(&rows, kind))
}

fn sqlite_conn_check_ok_canonical(
    conn: &mcp_agent_mail_db::CanonicalDbConn,
    kind: mcp_agent_mail_db::CheckKind,
) -> CliResult<bool> {
    let rows = sqlite_query_check_rows(
        |sql| conn.query_sync(sql, &[]).map_err(|e| e.to_string()),
        kind,
    )?;
    Ok(sqlite_pragma_check_rows_ok(&rows, kind))
}

fn sqlite_file_check_ok_canonical(
    db_path: &Path,
    kind: mcp_agent_mail_db::CheckKind,
) -> CliResult<bool> {
    let path_string = db_path.to_string_lossy().into_owned();
    let conn = mcp_agent_mail_db::CanonicalDbConn::open_file(&path_string).map_err(|e| {
        CliError::Other(format!(
            "cannot open sqlite file {} for canonical {kind}: {e}",
            db_path.display()
        ))
    })?;
    sqlite_conn_check_ok_canonical(&conn, kind)
}

fn sqlite_conn_check_ok_with_canonical_file_fallback(
    conn: &mcp_agent_mail_db::DbConn,
    db_path: &Path,
    kind: mcp_agent_mail_db::CheckKind,
) -> CliResult<bool> {
    let primary_result = sqlite_conn_check_ok(conn, kind);
    if primary_result.as_ref().is_ok_and(|ok| *ok) || db_path.as_os_str() == ":memory:" {
        return primary_result;
    }

    match sqlite_file_check_ok_canonical(db_path, kind) {
        Ok(true) => Ok(true),
        Ok(false) => Ok(false),
        Err(_) => match primary_result {
            Ok(false) => Ok(false),
            Ok(true) => Ok(true),
            Err(primary_error) => Err(primary_error),
        },
    }
}

fn sqlite_conn_quick_check_ok(conn: &mcp_agent_mail_db::DbConn) -> CliResult<bool> {
    sqlite_conn_check_ok(conn, mcp_agent_mail_db::CheckKind::Quick)
}

fn sqlite_conn_is_healthy(conn: &mcp_agent_mail_db::DbConn) -> CliResult<bool> {
    retry_sync_sqlite_lock(|| match sqlite_conn_quick_check_ok(conn) {
        Ok(ok) => Ok(ok),
        Err(e) => {
            let message = e.to_string();
            if is_sqlite_recovery_error_message(&message) {
                return Ok(false);
            }
            Err(sqlite_retryable_error(message.clone(), &message))
        }
    })
}

