struct CliMailboxReadLocks {
    _storage_root_lock: Option<mcp_agent_mail_server::MailboxActivityLockGuard>,
    _sqlite_lock: Option<mcp_agent_mail_server::MailboxActivityLockGuard>,
}

struct CliMailboxMutationLocks {
    _storage_root_lock: Option<mcp_agent_mail_server::MailboxActivityLockGuard>,
    _sqlite_lock: Option<mcp_agent_mail_server::MailboxActivityLockGuard>,
}

fn resolve_mailbox_activity_storage_root(storage_root_override: Option<&Path>) -> PathBuf {
    storage_root_override
        .map(PathBuf::from)
        .unwrap_or_else(|| Config::from_env().storage_root)
}

fn mailbox_activity_storage_root_is_explicit(
    storage_root: &Path,
    storage_root_override: Option<&Path>,
) -> bool {
    let explicit_override = storage_root_override.is_some()
        && !mcp_agent_mail_core::config::is_default_storage_root(storage_root);
    explicit_override || storage_root_is_effectively_explicit(storage_root)
}

fn storage_root_is_effectively_explicit(storage_root: &Path) -> bool {
    mcp_agent_mail_core::config::process_env_value("STORAGE_ROOT").is_some()
        && Config::from_env().storage_root == storage_root
        && !mcp_agent_mail_core::config::is_default_storage_root(storage_root)
}

fn should_lock_mailbox_storage_root(
    sqlite_path: &Path,
    storage_root: &Path,
    storage_root_override: Option<&Path>,
) -> bool {
    mailbox_activity_storage_root_is_explicit(storage_root, storage_root_override)
        || sqlite_path.starts_with(storage_root)
}

fn acquire_cli_mailbox_read_locks_for_paths(
    sqlite_path: &Path,
    storage_root: &Path,
) -> CliResult<CliMailboxReadLocks> {
    let storage_root_lock = acquire_cli_mailbox_activity_lock_for_storage_root(
        storage_root,
        mcp_agent_mail_server::MailboxActivityLockMode::Shared,
    )?;
    let sqlite_lock = acquire_cli_mailbox_activity_lock_for_sqlite_path(
        sqlite_path,
        mcp_agent_mail_server::MailboxActivityLockMode::Shared,
    )?;
    Ok(CliMailboxReadLocks {
        _storage_root_lock: storage_root_lock,
        _sqlite_lock: sqlite_lock,
    })
}

fn acquire_cli_mailbox_read_locks_for_sqlite_path(
    sqlite_path: &Path,
) -> CliResult<CliMailboxReadLocks> {
    let sqlite_lock = acquire_cli_mailbox_activity_lock_for_sqlite_path(
        sqlite_path,
        mcp_agent_mail_server::MailboxActivityLockMode::Shared,
    )?;
    Ok(CliMailboxReadLocks {
        _storage_root_lock: None,
        _sqlite_lock: sqlite_lock,
    })
}

fn acquire_cli_mailbox_read_locks(
    database_url: &str,
    _storage_root_override: Option<&Path>,
) -> CliResult<CliMailboxReadLocks> {
    // A live Agent Mail server holds the storage-root activity lock
    // exclusively for its lifetime to prevent a second runtime or mutating
    // doctor operation from starting. Read-only DB probes only need the SQLite
    // shared lock: it permits healthy server reads while still blocking against
    // repair/reconstruct swaps, which take the SQLite lock exclusively.
    let sqlite_path = resolve_mailbox_activity_sqlite_path(database_url)?;
    let sqlite_lock = acquire_cli_mailbox_activity_lock_for_sqlite_path(
        &sqlite_path,
        mcp_agent_mail_server::MailboxActivityLockMode::Shared,
    )?;
    Ok(CliMailboxReadLocks {
        _storage_root_lock: None,
        _sqlite_lock: sqlite_lock,
    })
}

fn acquire_cli_mailbox_mutation_locks(
    database_url: &str,
    storage_root_override: Option<&Path>,
) -> CliResult<CliMailboxMutationLocks> {
    let storage_root = resolve_mailbox_activity_storage_root(storage_root_override);
    let sqlite_path = resolve_mailbox_activity_sqlite_path(database_url)?;
    let storage_root_lock =
        if should_lock_mailbox_storage_root(&sqlite_path, &storage_root, storage_root_override) {
            acquire_doctor_mailbox_activity_lock_for_storage_root(&storage_root, false)?
        } else {
            None
        };
    let sqlite_lock = acquire_doctor_mailbox_activity_lock_for_database_url(database_url, false)?;
    Ok(CliMailboxMutationLocks {
        _storage_root_lock: storage_root_lock,
        _sqlite_lock: sqlite_lock,
    })
}

fn is_snapshot_conflict_cli_error(error: &CliError) -> bool {
    match error {
        CliError::Other(message) => {
            mcp_agent_mail_db::is_sqlite_snapshot_conflict_error_message(message)
        }
        _ => false,
    }
}

fn sqlite_conn_quick_check_ok_canonical(
    conn: &mcp_agent_mail_db::CanonicalDbConn,
) -> CliResult<bool> {
    sqlite_conn_check_ok_canonical(conn, mcp_agent_mail_db::CheckKind::Quick)
}

fn sqlite_conn_incremental_check_ok_canonical(
    conn: &mcp_agent_mail_db::CanonicalDbConn,
) -> CliResult<bool> {
    sqlite_conn_check_ok_canonical(conn, mcp_agent_mail_db::CheckKind::Incremental)
}

#[cfg(test)]
fn sqlite_file_has_live_sidecars(path: &Path) -> bool {
    for suffix in SQLITE_RECOVERY_SIDECAR_SUFFIXES {
        let sidecar = sqlite_sidecar_path(path, suffix);
        if let Ok(meta) = std::fs::metadata(&sidecar)
            && meta.len() > 0
        {
            return true;
        }
    }
    false
}

fn sqlite_file_is_healthy_canonical(path: &Path) -> CliResult<bool> {
    let path_string = path.to_string_lossy().into_owned();
    let conn = mcp_agent_mail_db::CanonicalDbConn::open_file(&path_string)
        .map_err(|e| CliError::Other(format!("cannot open sqlite file {}: {e}", path.display())))?;
    if !sqlite_conn_quick_check_ok_canonical(&conn)? {
        return Ok(false);
    }
    sqlite_conn_incremental_check_ok_canonical(&conn)
}

fn handle_sqlite_compatibility_probe_result(
    path: &Path,
    result: CliResult<bool>,
) -> CliResult<bool> {
    match result {
        Ok(ok) => Ok(ok),
        Err(e) => {
            let msg = e.to_string();
            if mcp_agent_mail_db::is_lock_error(&msg) {
                return Err(sqlite_doctor_busy_error(path, &msg));
            }
            if is_sqlite_recovery_error_message(&msg) {
                return Ok(false);
            }
            Err(e)
        }
    }
}

fn sqlite_file_is_healthy_with_compat_probe<F>(
    path: &Path,
    mut compatibility_probe: F,
) -> CliResult<bool>
where
    F: FnMut(&Path) -> CliResult<bool>,
{
    if !path.exists() {
        return Ok(true);
    }

    let path_string = path.to_string_lossy().into_owned();
    let conn = match mcp_agent_mail_db::DbConn::open_file(&path_string) {
        Ok(conn) => conn,
        Err(e) => {
            let err_text = e.to_string();
            if mcp_agent_mail_db::is_lock_error(&err_text) {
                return Err(sqlite_doctor_busy_error(path, &err_text));
            }
            if is_sqlite_recovery_error_message(&err_text)
                || mcp_agent_mail_db::is_sqlite_snapshot_conflict_error_message(&err_text)
            {
                return Ok(false);
            }
            return Err(CliError::Other(format!(
                "cannot open sqlite file {} for health check: {e}",
                path.display()
            )));
        }
    };

    let is_healthy = sqlite_conn_is_healthy(&conn)?;
    drop(conn);

    if !is_healthy {
        return handle_sqlite_compatibility_probe_result(path, compatibility_probe(path));
    }

    handle_sqlite_compatibility_probe_result(path, compatibility_probe(path))
}

fn sqlite_file_is_healthy(path: &Path) -> CliResult<bool> {
    sqlite_file_is_healthy_with_compat_probe(path, sqlite_file_is_healthy_canonical)
}

fn sqlite_file_is_healthy_read_only(path: &Path) -> CliResult<bool> {
    if !path.exists() {
        return Ok(true);
    }

    let conn = doctor_open_canonical_readonly_db_for_diagnostic(path, "health_check")?;
    if !sqlite_conn_quick_check_ok_canonical(&conn)? {
        return Ok(false);
    }
    sqlite_conn_incremental_check_ok_canonical(&conn)
}

fn sqlite_doctor_sanity_with_health_probe<F>(
    db_path: &str,
    mut health_probe: F,
) -> CliResult<(bool, String, bool, bool)>
where
    F: FnMut(&Path) -> CliResult<bool>,
{
    let mut selected_path = PathBuf::from(db_path);
    let mut used_absolute_fallback = false;
    let mut fallback_due_to_missing_configured_path = false;

    if !selected_path.exists() {
        if let Some(absolute_candidate) = sqlite_absolute_candidate_path(db_path) {
            selected_path = PathBuf::from(absolute_candidate);
            used_absolute_fallback = true;
            fallback_due_to_missing_configured_path = true;
        } else {
            return Ok((
                false,
                format!("Database file does not exist: {}", selected_path.display()),
                false,
                false,
            ));
        }
    }

    let mut healthy = match health_probe(selected_path.as_path()) {
        Ok(v) => v,
        Err(e) => {
            let msg = e.to_string();
            if is_snapshot_conflict_cli_error(&e) || is_sqlite_recovery_error_message(&msg) {
                false
            } else if mcp_agent_mail_db::is_lock_error(&msg) {
                return Err(sqlite_doctor_busy_error(selected_path.as_path(), &msg));
            } else {
                return Err(CliError::Other(format!(
                    "database health probe failed for {}: {msg}",
                    selected_path.display()
                )));
            }
        }
    };

    if !healthy
        && !used_absolute_fallback
        && let Some(absolute_candidate) = sqlite_absolute_candidate_path(db_path)
        && absolute_candidate != db_path
    {
        let absolute_path = PathBuf::from(&absolute_candidate);
        match health_probe(absolute_path.as_path()) {
            Ok(true) => {
                healthy = true;
                selected_path = absolute_path;
                used_absolute_fallback = true;
            }
            Ok(false) => {}
            Err(e) => {
                let msg = e.to_string();
                if is_snapshot_conflict_cli_error(&e) || is_sqlite_recovery_error_message(&msg) {
                } else if mcp_agent_mail_db::is_lock_error(&msg) {
                    return Err(sqlite_doctor_busy_error(selected_path.as_path(), &msg));
                } else {
                    return Err(CliError::Other(format!(
                        "database health probe failed for absolute fallback {}: {msg}",
                        absolute_path.display()
                    )));
                }
            }
        }
    }

    let file_size = selected_path.metadata().map(|m| m.len()).map_err(|e| {
        CliError::Other(format!(
            "cannot stat database file {}: {e}",
            selected_path.display()
        ))
    })?;
    if file_size == 0 {
        return Ok((
            false,
            "Database file is 0 bytes (empty/corrupt)".to_string(),
            used_absolute_fallback,
            fallback_due_to_missing_configured_path,
        ));
    }

    if healthy {
        if used_absolute_fallback {
            let detail = if fallback_due_to_missing_configured_path {
                format!(
                    "quick_check OK via absolute fallback {} (configured path missing; {} bytes)",
                    selected_path.display(),
                    file_size,
                )
            } else {
                format!(
                    "quick_check OK via absolute fallback {} ({} bytes)",
                    selected_path.display(),
                    file_size,
                )
            };
            return Ok((
                true,
                detail,
                used_absolute_fallback,
                fallback_due_to_missing_configured_path,
            ));
        }
        return Ok((
            true,
            format!("quick_check OK ({file_size} bytes)"),
            used_absolute_fallback,
            fallback_due_to_missing_configured_path,
        ));
    }

    Ok((
        false,
        format!(
            "Health probes failed for {} (possible corruption)",
            selected_path.display()
        ),
        used_absolute_fallback,
        fallback_due_to_missing_configured_path,
    ))
}

fn sqlite_doctor_file_sanity(db_path: &str) -> CliResult<(bool, String, bool, bool)> {
    sqlite_doctor_sanity_with_health_probe(db_path, sqlite_file_is_healthy)
}

fn sqlite_doctor_file_sanity_read_only(db_path: &str) -> CliResult<(bool, String, bool, bool)> {
    sqlite_doctor_sanity_with_health_probe(db_path, sqlite_file_is_healthy_read_only)
}

fn os_string_with_suffix(value: &OsStr, suffix: &str) -> OsString {
    let mut suffixed = value.to_os_string();
    suffixed.push(suffix);
    suffixed
}

fn path_with_file_name_suffix(path: &Path, suffix: &str, fallback: &str) -> PathBuf {
    match path.file_name() {
        Some(file_name) => path.with_file_name(os_string_with_suffix(file_name, suffix)),
        None => path.with_file_name(fallback),
    }
}

fn path_with_hidden_file_name_suffix(path: &Path, suffix: &str, fallback: &str) -> PathBuf {
    match path.file_name() {
        Some(file_name) => {
            let mut hidden_name = OsString::from(".");
            hidden_name.push(file_name);
            hidden_name.push(suffix);
            path.with_file_name(hidden_name)
        }
        None => path.with_file_name(fallback),
    }
}

fn next_sibling_staged_file_path(path: &Path, label: &str) -> PathBuf {
    let timestamp = chrono::Utc::now().format("%Y%m%d_%H%M%S_%3f").to_string();
    let mut candidate = path_with_hidden_file_name_suffix(
        path,
        &format!(".{label}-{timestamp}"),
        &format!(".artifact.{label}-{timestamp}"),
    );
    let mut suffix = 1_u32;
    while candidate.exists() {
        candidate = path_with_hidden_file_name_suffix(
            path,
            &format!(".{label}-{timestamp}-{suffix:02}"),
            &format!(".artifact.{label}-{timestamp}-{suffix:02}"),
        );
        suffix = suffix.saturating_add(1);
    }
    candidate
}

fn os_str_starts_with(value: &OsStr, prefix: &OsStr) -> bool {
    #[cfg(unix)]
    {
        use std::os::unix::ffi::OsStrExt as _;
        value.as_bytes().starts_with(prefix.as_bytes())
    }

    #[cfg(windows)]
    {
        use std::os::windows::ffi::OsStrExt as _;
        let value_units = value.encode_wide().collect::<Vec<_>>();
        let prefix_units = prefix.encode_wide().collect::<Vec<_>>();
        value_units.starts_with(&prefix_units)
    }

    #[cfg(not(any(unix, windows)))]
    {
        value
            .to_string_lossy()
            .starts_with(prefix.to_string_lossy().as_ref())
    }
}

fn os_str_ends_with(value: &OsStr, suffix: &OsStr) -> bool {
    #[cfg(unix)]
    {
        use std::os::unix::ffi::OsStrExt as _;
        value.as_bytes().ends_with(suffix.as_bytes())
    }

    #[cfg(windows)]
    {
        use std::os::windows::ffi::OsStrExt as _;
        let value_units = value.encode_wide().collect::<Vec<_>>();
        let suffix_units = suffix.encode_wide().collect::<Vec<_>>();
        value_units.ends_with(&suffix_units)
    }

    #[cfg(not(any(unix, windows)))]
    {
        value
            .to_string_lossy()
            .ends_with(suffix.to_string_lossy().as_ref())
    }
}

fn os_str_contains(value: &OsStr, needle: &OsStr) -> bool {
    #[cfg(unix)]
    {
        use std::os::unix::ffi::OsStrExt as _;
        let value_bytes = value.as_bytes();
        let needle_bytes = needle.as_bytes();
        needle_bytes.is_empty()
            || value_bytes
                .windows(needle_bytes.len())
                .any(|window| window == needle_bytes)
    }

    #[cfg(windows)]
    {
        use std::os::windows::ffi::OsStrExt as _;
        let value_units = value.encode_wide().collect::<Vec<_>>();
        let needle_units = needle.encode_wide().collect::<Vec<_>>();
        needle_units.is_empty()
            || value_units
                .windows(needle_units.len())
                .any(|window| window == needle_units)
    }

    #[cfg(not(any(unix, windows)))]
    {
        value
            .to_string_lossy()
            .contains(needle.to_string_lossy().as_ref())
    }
}

fn sqlite_backup_candidates(path: &Path) -> Vec<PathBuf> {
    let mut candidates: Vec<(std::time::SystemTime, bool, u8, PathBuf)> = Vec::new();
    let Some(file_name) = path.file_name() else {
        return Vec::new();
    };
    let parent = path.parent().unwrap_or_else(|| std::path::Path::new("."));
    let scan_dir = if parent.as_os_str().is_empty() {
        std::path::Path::new(".")
    } else {
        parent
    };

    let bak = path.with_file_name(os_string_with_suffix(file_name, ".bak"));
    if path_is_real_file(&bak) {
        let modified = bak
            .metadata()
            .and_then(|meta| meta.modified())
            .unwrap_or(std::time::SystemTime::UNIX_EPOCH);
        candidates.push((modified, true, 0, bak));
    }

    let backup_prefix = os_string_with_suffix(file_name, ".backup-");
    let backup_bak_prefix = os_string_with_suffix(file_name, ".bak.");
    let recovery_prefix = os_string_with_suffix(file_name, ".recovery");
    let sidecar_suffixes = SQLITE_RECOVERY_SIDECAR_SUFFIXES.map(OsString::from);
    if let Ok(entries) = std::fs::read_dir(scan_dir) {
        for entry in entries.flatten() {
            let candidate = entry.path();
            let Ok(file_type) = entry.file_type() else {
                continue;
            };
            if !file_type.is_file() || file_type.is_symlink() {
                continue;
            }
            let name = entry.file_name();

            let priority = if os_str_starts_with(&name, &backup_bak_prefix) {
                1
            } else if os_str_starts_with(&name, &backup_prefix) {
                2
            } else if os_str_starts_with(&name, &recovery_prefix) {
                3
            } else {
                continue;
            };
            if sidecar_suffixes
                .iter()
                .any(|suffix| os_str_ends_with(&name, suffix.as_os_str()))
            {
                continue;
            }
            let modified = entry
                .metadata()
                .and_then(|meta| meta.modified())
                .unwrap_or(std::time::SystemTime::UNIX_EPOCH);
            candidates.push((modified, false, priority, candidate));
        }
    }

    candidates.sort_by(|a, b| {
        b.0.cmp(&a.0)
            .then_with(|| a.1.cmp(&b.1))
            .then_with(|| a.2.cmp(&b.2))
            .then_with(|| b.3.cmp(&a.3))
    });
    candidates.into_iter().map(|(_, _, _, path)| path).collect()
}

fn find_healthy_sqlite_backup(path: &Path) -> Option<PathBuf> {
    for candidate in sqlite_backup_candidates(path) {
        if let Ok(true) = sqlite_file_is_healthy(&candidate) {
            return Some(candidate);
        }
    }
    None
}

// ─── br-bvq1x.11.1 (K1): loss-honest salvage/recover reporting ───────────────

/// Tables whose row counts are reported in salvage/recover loss reports so a
/// recovery can never silently imply it was lossless.
const SALVAGE_LOSS_REPORT_TABLES: &[&str] = &[
    "projects",
    "agents",
    "messages",
    "message_recipients",
    "file_reservations",
    "file_reservation_releases",
    "agent_links",
    "products",
    "product_project_links",
    "build_slots",
    "inbox_stats",
];

/// `(table, integer column)` pairs checked for suspect non-integer values that a
/// `sqlite3 .recover` salvage can inject (e.g. a TEXT id where an i64 is
/// expected). See br-bvq1x.11.1 L1 #7 (TEXT-id recipient fixture).
const SALVAGE_SUSPECT_TYPED_COLUMNS: &[(&str, &str)] = &[
    ("messages", "id"),
    ("agents", "id"),
    ("projects", "id"),
    ("message_recipients", "message_id"),
    ("message_recipients", "agent_id"),
    ("file_reservations", "id"),
];

/// Best-effort per-table row counts for a (possibly malformed) sqlite file.
/// Tables that cannot be counted are recorded as `Err(reason)` so the loss
/// report can say so honestly instead of pretending the count is zero.
#[derive(Debug, Clone, Default)]
struct SalvageRowCounts {
    counts: std::collections::BTreeMap<String, Result<i64, String>>,
    open_error: Option<String>,
}

/// Copy `path` into a throwaway temp dir and open the copy, so a malformed
/// ORIGINAL is never opened read-write (no sidecar creation, no mutation).
/// `on_error` receives a human reason when the copy cannot be opened/read.
fn with_salvage_readonly_copy<T>(
    path: &Path,
    on_conn: impl FnOnce(&mcp_agent_mail_db::DbConn) -> T,
    on_error: impl FnOnce(String) -> T,
) -> T {
    if !path.exists() {
        return on_error(format!("file does not exist: {}", path.display()));
    }
    let tmp = match tempfile::tempdir() {
        Ok(dir) => dir,
        Err(e) => return on_error(format!("salvage loss-count tempdir failed: {e}")),
    };
    let copy = tmp.path().join("losscount.sqlite3");
    if let Err(e) = std::fs::copy(path, &copy) {
        return on_error(format!(
            "copy {} for loss-count failed: {e}",
            path.display()
        ));
    }
    // Copy WAL/SHM sidecars alongside so the copy reflects pending WAL frames;
    // counting only the main file would understate (and thus mis-report) loss.
    for suffix in ["-wal", "-shm"] {
        let sidecar = sqlite_sidecar_path(path, suffix);
        if sidecar.exists() {
            let _ = std::fs::copy(&sidecar, sqlite_sidecar_path(&copy, suffix));
        }
    }
    match open_sqlite_read_only_with_fallback(&copy.to_string_lossy()) {
        Ok((conn, _opened)) => on_conn(&conn),
        Err(e) => on_error(e.to_string()),
    }
}

/// Count rows in each [`SALVAGE_LOSS_REPORT_TABLES`] table, tolerating a
/// malformed/partially-readable database (per-table errors become
/// `Err(reason)`; a total open failure marks every table uncountable).
fn count_salvage_rows(path: &Path) -> SalvageRowCounts {
    with_salvage_readonly_copy(
        path,
        |conn| {
            let mut counts = std::collections::BTreeMap::new();
            for table in SALVAGE_LOSS_REPORT_TABLES {
                let sql = format!("SELECT COUNT(*) AS cnt FROM {table}");
                let res = match conn.query_sync(&sql, &[]) {
                    Ok(rows) => rows
                        .first()
                        .and_then(|row| row.get_named::<i64>("cnt").ok())
                        .map_or_else(|| Err("count returned no rows".to_string()), Ok),
                    Err(e) => Err(e.to_string()),
                };
                counts.insert((*table).to_string(), res);
            }
            SalvageRowCounts {
                counts,
                open_error: None,
            }
        },
        |err| {
            let mut counts = std::collections::BTreeMap::new();
            for table in SALVAGE_LOSS_REPORT_TABLES {
                counts.insert(
                    (*table).to_string(),
                    Err("database could not be opened".to_string()),
                );
            }
            SalvageRowCounts {
                counts,
                open_error: Some(err),
            }
        },
    )
}

/// Detect rows whose supposedly-integer id/fk columns hold a non-integer
/// (typically TEXT) value — the hallmark of a `sqlite3 .recover` salvage.
/// Tables/columns that do not exist are silently skipped.
fn detect_salvage_suspect_typed_rows(path: &Path) -> Vec<String> {
    with_salvage_readonly_copy(
        path,
        |conn| {
            let mut suspects = Vec::new();
            for (table, column) in SALVAGE_SUSPECT_TYPED_COLUMNS {
                let sql = format!(
                    "SELECT COUNT(*) AS cnt FROM {table} WHERE typeof({column}) <> 'integer'"
                );
                if let Ok(rows) = conn.query_sync(&sql, &[])
                    && let Some(count) = rows
                        .first()
                        .and_then(|row| row.get_named::<i64>("cnt").ok())
                    && count > 0
                {
                    suspects.push(format!(
                        "{table}.{column}: {count} row(s) with non-integer (suspect) value"
                    ));
                }
            }
            suspects
        },
        |_err| Vec::new(),
    )
}

/// Pure diff of countable tables: returns `(total_rows_lost, per-table lost
/// detail)`. Only tables countable in BOTH snapshots contribute; growth is not
/// counted as loss.
fn salvage_total_lost(before: &SalvageRowCounts, after: &SalvageRowCounts) -> (i64, Vec<String>) {
    let mut total = 0i64;
    let mut lost = Vec::new();
    for table in SALVAGE_LOSS_REPORT_TABLES {
        if let (Some(Ok(b)), Some(Ok(a))) = (before.counts.get(*table), after.counts.get(*table))
            && a < b
        {
            let delta = b - a;
            total += delta;
            lost.push(format!("{table}: {b} -> {a} (LOST {delta})"));
        }
    }
    (total, lost)
}

/// Tables that could not be counted in `before` (e.g. corruption prevented it) —
/// the operator must know these were never accounted for.
fn salvage_uncountable_tables(counts: &SalvageRowCounts) -> Vec<String> {
    counts
        .counts
        .iter()
        .filter_map(|(table, res)| res.as_ref().err().map(|_| table.clone()))
        .collect()
}

/// Emit the loss-honest salvage report to stderr. Framed as an EMERGENCY path —
/// never implies a clean self-heal when data was lost.
fn emit_salvage_loss_report(
    mode: &str,
    before: &SalvageRowCounts,
    after: &SalvageRowCounts,
    suspect_rows: &[String],
) {
    let render = |entry: Option<&Result<i64, String>>| -> String {
        match entry {
            Some(Ok(n)) => n.to_string(),
            Some(Err(_)) => "uncountable".to_string(),
            None => "n/a".to_string(),
        }
    };
    let mut lines: Vec<String> = vec![format!(
        "EMERGENCY RECOVERY ({mode}) — this is NOT a clean self-heal; verify the per-table loss report:"
    )];
    if let Some(err) = &before.open_error {
        lines.push(format!(
            "  pre-recovery database could not be fully counted: {err}"
        ));
    }
    for table in SALVAGE_LOSS_REPORT_TABLES {
        lines.push(format!(
            "  {table:<27} before={:<12} after={}",
            render(before.counts.get(*table)),
            render(after.counts.get(*table)),
        ));
    }
    let (total_lost, lost_detail) = salvage_total_lost(before, after);
    if total_lost > 0 {
        lines.push(format!(
            ">>> ROWS LOST during recovery: {total_lost} (rows present pre-recovery but absent after)"
        ));
        for detail in &lost_detail {
            lines.push(format!("    - {detail}"));
        }
    } else {
        lines.push(
            "  no row loss detected across tables countable both before and after".to_string(),
        );
    }
    let uncountable_before = salvage_uncountable_tables(before);
    if !uncountable_before.is_empty() {
        lines.push(format!(
            "  tables that could NOT be counted pre-recovery (loss for these is UNKNOWN): {}",
            uncountable_before.join(", ")
        ));
    }
    if !suspect_rows.is_empty() {
        lines.push(
            "  suspect recovered rows (non-integer ids — likely sqlite3 .recover salvage):"
                .to_string(),
        );
        for suspect in suspect_rows {
            lines.push(format!("    - {suspect}"));
        }
    }
    lines.push(
        "  Recovery rebuilds from the Git archive + best-effort salvage; rows absent from both are unrecoverable. Inspect the quarantined original before discarding it."
            .to_string(),
    );
    ftui_runtime::ftui_eprintln!("{}", lines.join("\n"));
}

#[cfg(test)]
fn recover_sqlite_file(path: &Path) -> CliResult<()> {
    recover_sqlite_file_with_storage_root(path, None)
}

fn recover_sqlite_file_with_storage_root(
    path: &Path,
    storage_root_override: Option<&Path>,
) -> CliResult<()> {
    let storage_root = resolve_mailbox_activity_storage_root(storage_root_override);
    if !path.exists() {
        return Ok(());
    }
    validate_real_file_target_path(path, "recovery destination")?;
    if sqlite_file_is_healthy(path)? {
        reconcile_sqlite_file_with_archive(path, &storage_root)?;
        return Ok(());
    }

    let backup = find_healthy_sqlite_backup(path);

    // br-bvq1x.11.1 (K1): capture best-effort pre-recovery row counts from the
    // (possibly malformed) original BEFORE we replace it, so the loss report can
    // be honest about what recovery could and could not preserve.
    let salvage_before = count_salvage_rows(path);

    // br-bvq1x.11.2 (K2): prefer the last-known-healthy VERIFIED snapshot — a
    // backup that passed a full integrity check and carries metadata — as the
    // fast, lossless recovery path before falling back to a generic backup or an
    // archive rebuild. The restore re-verifies the snapshot before trusting it.
    match mcp_agent_mail_db::snapshot::restore_from_verified_snapshot(path, &storage_root) {
        Ok(Some(meta)) => {
            reconcile_sqlite_file_with_archive(path, &storage_root)?;
            let salvage_after = count_salvage_rows(path);
            let suspect_rows = detect_salvage_suspect_typed_rows(path);
            ftui_runtime::ftui_println!(
                "Recovered from verified snapshot (taken {} UTC, full integrity-check verified, {} message rows).",
                mcp_agent_mail_core::timestamps::micros_to_iso(meta.created_us),
                meta.row_counts.get("messages").copied().unwrap_or(0),
            );
            emit_salvage_loss_report(
                "verified-snapshot-restore",
                &salvage_before,
                &salvage_after,
                &suspect_rows,
            );
            return Ok(());
        }
        Ok(None) => {
            // No trustworthy verified snapshot; fall through to backup/archive.
        }
        Err(err) => {
            ftui_runtime::ftui_eprintln!(
                "Warning: verified-snapshot restore failed ({err}); falling back to backup/archive recovery."
            );
        }
    }

    if let Some(backup_path) = backup {
        // Safety: copy backup to a temp path first, validate it, then
        // quarantine the original and swap in the validated copy.  This
        // ensures the original DB is never removed until the replacement
        // is known-good (same pattern as the reconstruct path below).
        let temp_restore = next_doctor_artifact_path(path, "restore", "sqlite3");
        std::fs::copy(&backup_path, &temp_restore).map_err(|e| {
            CliError::Other(format!(
                "failed to copy sqlite backup {} to temp path {}: {e}",
                backup_path.display(),
                temp_restore.display()
            ))
        })?;
        if !sqlite_file_is_healthy(&temp_restore)? {
            cleanup_doctor_temp_sqlite_artifact(&temp_restore);
            return Err(CliError::Other(format!(
                "sqlite backup {} did not pass health check after copy (original is untouched)",
                backup_path.display()
            )));
        }
        // Count the validated replacement BEFORE swapping it in.
        let salvage_after = count_salvage_rows(&temp_restore);
        let suspect_rows = detect_salvage_suspect_typed_rows(&temp_restore);
        mcp_agent_mail_db::promote_recovery_candidate(path, &temp_restore, &storage_root).map_err(
            |error| {
                CliError::Other(format!(
                    "validated sqlite backup promotion failed for {}: {error}",
                    path.display()
                ))
            },
        )?;
        reconcile_sqlite_file_with_archive(path, &storage_root)?;
        emit_salvage_loss_report(
            "backup-restore",
            &salvage_before,
            &salvage_after,
            &suspect_rows,
        );
    } else {
        // Fall back to archive reconstruction if no backup is available and
        // the archive is authoritative for this SQLite path.
        // Safety (issue #59): reconstruct into a temp file first, validate it,
        // then quarantine the original and swap in the new one. The original DB
        // is NOT moved/modified until the new DB is proven healthy.
        let archive_inventory = collect_doctor_archive_inventory(&storage_root);
        let archive_has_state = archive_inventory.counts() != DoctorInventoryCounts::default();
        let storage_root_is_explicit =
            mailbox_activity_storage_root_is_explicit(&storage_root, storage_root_override);
        let archive_reconstruct_available = storage_root.is_dir()
            && archive_has_state
            && doctor_archive_is_authoritative_for_sqlite_path(
                path,
                &storage_root,
                storage_root_is_explicit,
            );
        if archive_reconstruct_available {
            ftui_runtime::ftui_println!(
                "No backup found. Reconstructing database from archive at {}...",
                storage_root.display()
            );
            // Attempt best-effort salvage from the original DB and nearby
            // doctor artifacts while the live file is still in place. A prior
            // quarantine can contain cleaner DB-only state than the current
            // malformed file, so keep startup recovery aligned with the manual
            // `am doctor reconstruct` salvage candidate order.
            let salvage_attempt = attempt_best_doctor_salvage_artifact(path);
            let salvage_db_path = match &salvage_attempt {
                DoctorSalvageAttempt::Succeeded(artifact) => Some(artifact.db_path.as_path()),
                DoctorSalvageAttempt::Failed(detail) => {
                    ftui_runtime::ftui_eprintln!(
                        "Warning: best-effort sqlite salvage failed for {}: {detail}",
                        path.display()
                    );
                    None
                }
            };
            // Reconstruct into a temp file so the original is untouched on failure.
            let temp_reconstruct = next_doctor_artifact_path(path, "reconstruct", "sqlite3");
            match mcp_agent_mail_db::reconstruct_from_archive_with_salvage(
                &temp_reconstruct,
                &storage_root,
                salvage_db_path,
            ) {
                Ok(mut stats) => {
                    if let DoctorSalvageAttempt::Succeeded(artifact) = &salvage_attempt {
                        stats.warnings.push(artifact.detail.clone());
                    }
                    ftui_runtime::ftui_println!("Reconstruction complete: {}", stats);
                    if !stats.warnings.is_empty() {
                        for warning in &stats.warnings {
                            ftui_runtime::ftui_eprintln!("Warning: {warning}");
                        }
                    }
                    if !sqlite_file_is_healthy(&temp_reconstruct)? {
                        cleanup_doctor_temp_sqlite_artifact(&temp_reconstruct);
                        return Err(CliError::Other(format!(
                            "reconstruction from archive completed, but health checks \
                             still failed (original database is untouched at {})",
                            path.display()
                        )));
                    }
                    // br-bvq1x.11.1 (K1): count the reconstructed DB before swap
                    // and report any loss vs the pre-recovery original.
                    let salvage_after = count_salvage_rows(&temp_reconstruct);
                    let suspect_rows = detect_salvage_suspect_typed_rows(&temp_reconstruct);
                    mcp_agent_mail_db::promote_recovery_candidate(
                        path,
                        &temp_reconstruct,
                        &storage_root,
                    )
                    .map_err(|error| {
                        CliError::Other(format!(
                            "validated archive reconstruction promotion failed for {}: {error}",
                            path.display()
                        ))
                    })?;
                    reconcile_sqlite_file_with_archive(path, &storage_root)?;
                    emit_salvage_loss_report(
                        "archive-reconstruct",
                        &salvage_before,
                        &salvage_after,
                        &suspect_rows,
                    );
                }
                Err(e) => {
                    // Clean up partial temp file; original is safe.
                    cleanup_doctor_temp_sqlite_artifact(&temp_reconstruct);
                    return Err(CliError::Other(format!(
                        "failed to reconstruct database from archive \
                         (original database is untouched): {e}"
                    )));
                }
            }
        } else {
            return Err(CliError::Other(format!(
                "database {} is unhealthy, no healthy backup was found, and no authoritative archive data exists under {} for this database path; original database is untouched",
                path.display(),
                storage_root.display()
            )));
        }
    }

    Ok(())
}

fn reconcile_sqlite_file_with_archive(path: &Path, storage_root: &Path) -> CliResult<()> {
    mcp_agent_mail_db::ensure_sqlite_file_healthy_with_archive(path, storage_root).map_err(|e| {
        CliError::Other(format!(
            "archive-aware sqlite reconciliation failed for {}: {e}",
            path.display()
        ))
    })
}

fn ensure_sqlite_parent_dir(path: &Path) -> CliResult<()> {
    if let Some(parent) = path.parent()
        && !parent.as_os_str().is_empty()
        && !parent.exists()
    {
        std::fs::create_dir_all(parent).map_err(|e| {
            CliError::Other(format!("failed to create db dir {}: {e}", parent.display()))
        })?;
    }
    Ok(())
}

fn sqlite_path_is_explicit_relative(path: &Path) -> bool {
    matches!(
        path.components().next(),
        Some(std::path::Component::CurDir) | Some(std::path::Component::ParentDir)
    )
}

fn sqlite_absolute_fallback_path(path: &str, open_error: &str) -> Option<String> {
    let parsed_path = Path::new(path);
    if path == ":memory:"
        || parsed_path.is_absolute()
        || sqlite_path_is_explicit_relative(parsed_path)
        || !is_sqlite_corruption_error_message(open_error)
    {
        return None;
    }
    let absolute_candidate = Path::new("/").join(parsed_path);
    if !absolute_candidate.is_file() {
        return None;
    }
    Some(absolute_candidate.to_string_lossy().into_owned())
}

fn sqlite_absolute_candidate_path(path: &str) -> Option<String> {
    let parsed_path = Path::new(path);
    if path == ":memory:"
        || parsed_path.is_absolute()
        || sqlite_path_is_explicit_relative(parsed_path)
    {
        return None;
    }
    let absolute_candidate = Path::new("/").join(parsed_path);
    if !absolute_candidate.is_file() {
        return None;
    }
    Some(absolute_candidate.to_string_lossy().into_owned())
}

fn resolve_sqlite_path_with_absolute_candidate(path: &str) -> String {
    let mut resolved = path.to_string();
    if resolved != ":memory:"
        && !Path::new(&resolved).exists()
        && let Some(absolute_path) = sqlite_absolute_candidate_path(&resolved)
    {
        resolved = absolute_path;
    }
    resolved
}

fn open_sqlite_with_fallback(path: &str) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    open_sqlite_with_fallback_and_storage_root(path, None)
}

fn open_sqlite_read_only_with_fallback(
    path: &str,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    open_sqlite_with_fallback_internal(path, None, false)
}

const SQLITE_DATABASE_HEADER_BYTES: usize = 100;

fn require_existing_regular_sqlite_source(path: &Path, context: &str) -> CliResult<()> {
    if path == Path::new(":memory:") {
        return Err(CliError::Other(format!(
            "{context} requires an existing file-backed SQLite database; :memory: cannot be snapshotted"
        )));
    }

    let metadata = std::fs::symlink_metadata(path).map_err(|error| {
        if error.kind() == std::io::ErrorKind::NotFound {
            CliError::Other(format!(
                "{context} requires an existing file-backed SQLite database; not found: {}",
                path.display()
            ))
        } else {
            CliError::Other(format!(
                "{context} failed to inspect SQLite source {}: {error}",
                path.display()
            ))
        }
    })?;

    if !metadata.file_type().is_file() {
        return Err(CliError::Other(format!(
            "{context} live snapshot source must be a regular SQLite file; refusing {}",
            path.display()
        )));
    }

    if metadata.len() < SQLITE_DATABASE_HEADER_BYTES as u64 {
        return Err(CliError::Other(format!(
            "{context} requires an existing valid SQLite database; {} is too small to contain a SQLite header",
            path.display()
        )));
    }

    let mut header = [0_u8; SQLITE_DATABASE_HEADER_BYTES];
    let mut file = doctor::platform::open_regular_file_no_follow(path).map_err(|error| {
        CliError::Other(format!(
            "{context} failed to read SQLite source header {}: {error}",
            path.display()
        ))
    })?;
    let open_metadata = file.metadata().map_err(|error| {
        CliError::Other(format!(
            "{context} failed to inspect opened SQLite source {}: {error}",
            path.display()
        ))
    })?;
    if !open_metadata.file_type().is_file() {
        return Err(CliError::Other(format!(
            "{context} opened live snapshot source must be a regular SQLite file; refusing {}",
            path.display()
        )));
    }
    if open_metadata.len() < SQLITE_DATABASE_HEADER_BYTES as u64 {
        return Err(CliError::Other(format!(
            "{context} requires an existing valid SQLite database; {} is too small to contain a SQLite header",
            path.display()
        )));
    }
    std::io::Read::read_exact(&mut file, &mut header).map_err(|error| {
        CliError::Other(format!(
            "{context} failed to read SQLite source header {}: {error}",
            path.display()
        ))
    })?;
    if &header[..16] != b"SQLite format 3\0" {
        return Err(CliError::Other(format!(
            "{context} requires an existing valid SQLite database; {} has an invalid SQLite header",
            path.display()
        )));
    }

    Ok(())
}

fn resolve_existing_sqlite_source_candidate_with_database_url(
    database_url: &str,
    context: &str,
) -> CliResult<PathBuf> {
    let cfg = mcp_agent_mail_db::DbPoolConfig {
        database_url: database_url.to_string(),
        ..Default::default()
    };
    let path = cfg
        .sqlite_path()
        .map_err(|error| CliError::Other(format!("bad database URL: {error}")))?;
    let path = resolve_sqlite_path_with_absolute_candidate(&path);
    let source_candidate = PathBuf::from(path);
    require_existing_regular_sqlite_source(&source_candidate, context)?;
    Ok(source_candidate)
}

fn validated_live_sqlite_snapshot_source_path_from_candidate(
    source_candidate: &Path,
    context: &str,
) -> CliResult<PathBuf> {
    require_existing_regular_sqlite_source(source_candidate, context)?;
    Ok(source_candidate.to_path_buf())
}

fn open_sqlite_with_fallback_and_storage_root(
    path: &str,
    storage_root_override: Option<&Path>,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    open_sqlite_with_fallback_internal(path, storage_root_override, true)
}

fn open_sqlite_with_fallback_internal(
    path: &str,
    storage_root_override: Option<&Path>,
    allow_recovery: bool,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    let open_conn = |candidate: &str| -> Result<mcp_agent_mail_db::DbConn, String> {
        let conn = if candidate == ":memory:" {
            mcp_agent_mail_db::DbConn::open_memory().map_err(|e| e.to_string())?
        } else {
            mcp_agent_mail_db::DbConn::open_file(candidate).map_err(|e| e.to_string())?
        };
        conn.execute_raw(mcp_agent_mail_db::schema::PRAGMA_CONN_SETTINGS_SQL)
            .map_err(|e| e.to_string())?;
        Ok(conn)
    };

    retry_sync_sqlite_lock(|| match open_conn(path) {
        Ok(conn) => Ok((conn, path.to_string())),
        Err(primary_err) => {
            let primary_err_text = primary_err.to_string();
            if let Some(fallback_path) = sqlite_absolute_fallback_path(path, &primary_err_text) {
                let fallback_conn = open_conn(&fallback_path).map_err(|fallback_err| {
                        sqlite_retryable_error(
                            format!(
                                "cannot open DB at {path}: {primary_err}; fallback {fallback_path} failed: {fallback_err}"
                            ),
                            &fallback_err.to_string(),
                        )
                    })?;
                return Ok((fallback_conn, fallback_path));
            }
            if allow_recovery
                && path != ":memory:"
                && is_sqlite_recovery_error_message(&primary_err_text)
            {
                let primary_path = Path::new(path);
                recover_sqlite_file_with_storage_root(primary_path, storage_root_override).map_err(
                    |recovery_err| {
                    sqlite_retryable_error(
                        format!(
                            "cannot open DB at {path}: {primary_err}; auto-recovery failed: {recovery_err}"
                        ),
                        &recovery_err.to_string(),
                    )
                },
                )?;
                let recovered_conn = open_conn(path).map_err(|e| {
                    sqlite_retryable_error(
                        format!(
                            "cannot open DB at {path}: {primary_err}; auto-recovery reopen failed: {e}"
                        ),
                        &e.to_string(),
                    )
                })?;
                return Ok((recovered_conn, path.to_string()));
            }
            Err(sqlite_retryable_error(
                format!("cannot open DB at {path}: {primary_err}"),
                &primary_err_text,
            ))
        }
    })
}

fn init_schema_sqlite_canonical(path: &str) -> CliResult<()> {
    retry_sync_sqlite_lock(|| {
        let conn = mcp_agent_mail_db::CanonicalDbConn::open_file(path).map_err(|e| {
            sqlite_retryable_error(
                format!("cannot open DB at {path} for schema init: {e}"),
                &e.to_string(),
            )
        })?;
        conn.execute_raw("PRAGMA busy_timeout = 60000;")
            .map_err(|e| {
                sqlite_retryable_error(
                    format!(
                        "failed to apply busy_timeout for {path} during canonical schema init: {e}"
                    ),
                    &e.to_string(),
                )
            })?;
        conn.execute_raw(mcp_agent_mail_db::schema::PRAGMA_DB_INIT_BASE_SQL)
            .map_err(|e| {
                sqlite_retryable_error(
                    format!(
                        "failed to apply base init PRAGMAs for {path} during canonical schema init: {e}"
                    ),
                    &e.to_string(),
                )
            })?;
        let init_sql = mcp_agent_mail_db::schema::init_schema_sql_base();
        conn.execute_raw(&init_sql).map_err(|e| {
            sqlite_retryable_error(
                format!("schema init failed for {path} during canonical schema init: {e}"),
                &e.to_string(),
            )
        })?;

        conn.execute_raw(&format!(
            "CREATE TABLE IF NOT EXISTS {} (\
                id TEXT PRIMARY KEY ON CONFLICT IGNORE,\
                description TEXT NOT NULL,\
                applied_at INTEGER NOT NULL\
            )",
            mcp_agent_mail_db::schema::MIGRATIONS_TABLE_NAME,
        ))
        .map_err(|e| {
            sqlite_retryable_error(
                format!("failed to initialize migrations table for {path}: {e}"),
                &e.to_string(),
            )
        })?;

        let migration_ts = mcp_agent_mail_db::timestamps::now_micros();
        for migration in mcp_agent_mail_db::schema::schema_migrations_base() {
            if let Err(e) = conn.execute_raw(&migration.up) {
                let err_text = e.to_string();
                if !sqlite_migration_error_is_benign(&err_text) {
                    return Err(sqlite_retryable_error(
                        format!(
                            "failed to apply base migration {} for {path}: {e}",
                            migration.id
                        ),
                        &err_text,
                    ));
                }
            }
            conn.execute_sync(
                &format!(
                    "INSERT OR IGNORE INTO {} (id, description, applied_at) VALUES (?, ?, ?)",
                    mcp_agent_mail_db::schema::MIGRATIONS_TABLE_NAME,
                ),
                &[
                    sqlmodel_core::Value::Text(migration.id),
                    sqlmodel_core::Value::Text(migration.description),
                    sqlmodel_core::Value::BigInt(migration_ts),
                ],
            )
            .map_err(|e| {
                sqlite_retryable_error(
                    format!("failed to record base migration for {path}: {e}"),
                    &e.to_string(),
                )
            })?;
        }
        drop(conn);
        mcp_agent_mail_db::pool::wal_checkpoint_truncate_path(std::path::Path::new(path)).map_err(
            |e| {
                sqlite_retryable_error(
                    format!("failed to checkpoint canonical init for {path}: {e}"),
                    &e.to_string(),
                )
            },
        )?;
        Ok(())
    })
}

fn sqlite_migration_error_is_benign(message: &str) -> bool {
    let lower = message.to_ascii_lowercase();
    lower.contains("already exists")
        || lower.contains("duplicate column name")
        || lower.contains("duplicate trigger name")
}

fn sqlite_retryable_error(message: String, detail: &str) -> mcp_agent_mail_db::DbError {
    if mcp_agent_mail_db::is_lock_error(detail) {
        mcp_agent_mail_db::DbError::ResourceBusy(message)
    } else {
        mcp_agent_mail_db::DbError::Sqlite(message)
    }
}

fn retry_sync_sqlite_lock<T, F>(op: F) -> CliResult<T>
where
    F: FnMut() -> mcp_agent_mail_db::DbResult<T>,
{
    let config = mcp_agent_mail_db::RetryConfig {
        use_circuit_breaker: false,
        ..Default::default()
    };
    mcp_agent_mail_db::retry_sync(&config, op).map_err(|e| match e {
        mcp_agent_mail_db::DbError::ResourceBusy(message) => CliError::Other(format!(
            "Resource is temporarily busy. Wait a moment and try again. ({message})"
        )),
        mcp_agent_mail_db::DbError::Sqlite(message)
        | mcp_agent_mail_db::DbError::Pool(message)
        | mcp_agent_mail_db::DbError::Schema(message)
        | mcp_agent_mail_db::DbError::Serialization(message)
        | mcp_agent_mail_db::DbError::Internal(message) => CliError::Other(message),
        other => CliError::Other(other.to_string()),
    })
}

/// Open a synchronous SQLite connection for CLI commands.
pub(crate) fn open_db_sync_with_database_url(
    database_url: &str,
) -> CliResult<mcp_agent_mail_db::DbConn> {
    open_db_sync_with_database_url_with_path(database_url).map(|(conn, _opened_path)| conn)
}

fn open_db_sync_with_database_url_with_path(
    database_url: &str,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    open_db_sync_with_database_url_and_storage_root_with_path(database_url, None)
}

#[cfg_attr(not(test), allow(dead_code))]
fn open_db_sync_with_database_url_and_storage_root(
    database_url: &str,
    storage_root_override: Option<&Path>,
) -> CliResult<mcp_agent_mail_db::DbConn> {
    open_db_sync_with_database_url_and_storage_root_with_path(database_url, storage_root_override)
        .map(|(conn, _opened_path)| conn)
}

fn open_db_sync_with_database_url_and_storage_root_with_path(
    database_url: &str,
    storage_root_override: Option<&Path>,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    open_db_sync_with_database_url_and_storage_root_internal(
        database_url,
        storage_root_override,
        true,
    )
}

fn open_db_sync_with_database_url_and_storage_root_locked(
    database_url: &str,
    storage_root_override: Option<&Path>,
) -> CliResult<mcp_agent_mail_db::DbConn> {
    open_db_sync_with_database_url_and_storage_root_internal(
        database_url,
        storage_root_override,
        false,
    )
    .map(|(conn, _opened_path)| conn)
}

fn open_db_sync_with_database_url_and_storage_root_internal(
    database_url: &str,
    storage_root_override: Option<&Path>,
    acquire_mutation_locks: bool,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    let cfg = mcp_agent_mail_db::DbPoolConfig {
        database_url: database_url.to_string(),
        ..Default::default()
    };
    let path = cfg
        .sqlite_path()
        .map_err(|e| CliError::Other(format!("bad database URL: {e}")))?;
    let path = resolve_sqlite_path_with_absolute_candidate(&path);
    if path != ":memory:" {
        ensure_sqlite_parent_dir(Path::new(&path))?;
    }
    let read_only_open = open_sqlite_read_only_with_fallback(&path);
    if let Ok((conn, opened_path)) = read_only_open {
        if opened_path == ":memory:" {
            return Ok((conn, opened_path));
        }

        if !sqlite_conn_requires_canonical_init(&conn)? && sqlite_conn_is_healthy(&conn)? {
            return maybe_reconcile_sync_opened_sqlite_archive_drift(
                conn,
                opened_path,
                database_url,
                storage_root_override,
                acquire_mutation_locks,
            );
        }

        drop(conn);
    }

    let _mailbox_mutation_locks = if acquire_mutation_locks {
        Some(acquire_cli_mailbox_mutation_locks(
            database_url,
            storage_root_override,
        )?)
    } else {
        None
    };
    let (mut conn, mut opened_path) =
        open_sqlite_with_fallback_and_storage_root(&path, storage_root_override)?;
    if opened_path != ":memory:" {
        if !sqlite_conn_requires_canonical_init(&conn)? {
            return maybe_reconcile_sync_opened_sqlite_archive_drift(
                conn,
                opened_path,
                database_url,
                storage_root_override,
                false,
            );
        }

        let mut conn_healthy = sqlite_conn_is_healthy(&conn)?;
        if !conn_healthy {
            // If a malformed relative path shadows a healthy absolute DB, prefer that absolute file
            // before mutating/quarantining the relative artifact.
            if let Some(absolute_path) = sqlite_absolute_candidate_path(&opened_path)
                && absolute_path != opened_path
                && let Ok(fallback_conn) = mcp_agent_mail_db::DbConn::open_file(&absolute_path)
                && sqlite_conn_is_healthy(&fallback_conn)?
            {
                conn = fallback_conn;
                opened_path = absolute_path;
                conn_healthy = true;
            }

            if !conn_healthy {
                drop(conn);
                recover_sqlite_file_with_storage_root(
                    Path::new(&opened_path),
                    storage_root_override,
                )?;
                conn = mcp_agent_mail_db::DbConn::open_file(&opened_path).map_err(|e| {
                    CliError::Other(format!("cannot reopen DB at {opened_path}: {e}"))
                })?;
            }
        }

        // For file-backed DBs, run canonical schema bootstrap only when the file is
        // empty/partial/recovered. Re-running write-heavy init on every `am robot`
        // command turns read-mostly status calls into avoidable lock contention.
        drop(conn);
        if let Err(init_error) = init_schema_sqlite_canonical(&opened_path) {
            let init_error_text = init_error.to_string();
            if is_sqlite_recovery_error_message(&init_error_text) {
                recover_sqlite_file_with_storage_root(
                    Path::new(&opened_path),
                    storage_root_override,
                )?;
                init_schema_sqlite_canonical(&opened_path)?;
            } else {
                return Err(init_error);
            }
        }
        let (reopened, resolved_path) = open_sqlite_with_fallback(&opened_path)?;
        return maybe_reconcile_sync_opened_sqlite_archive_drift(
            reopened,
            resolved_path,
            database_url,
            storage_root_override,
            false,
        );
    }

    // In-memory DBs keep the original Franken init path.
    let init_sql = mcp_agent_mail_db::schema::init_schema_sql_base();
    conn.execute_raw(&init_sql)
        .map_err(|e| CliError::Other(format!("schema init failed for {opened_path}: {e}")))?;
    Ok((conn, opened_path))
}

fn maybe_reconcile_sync_opened_sqlite_archive_drift(
    conn: mcp_agent_mail_db::DbConn,
    opened_path: String,
    database_url: &str,
    storage_root_override: Option<&Path>,
    acquire_mutation_locks: bool,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    if opened_path == ":memory:" {
        return Ok((conn, opened_path));
    }

    let storage_root = resolve_mailbox_activity_storage_root(storage_root_override);
    let storage_root_is_explicit =
        mailbox_activity_storage_root_is_explicit(&storage_root, storage_root_override);
    if !path_is_real_directory(&storage_root.join("projects")) {
        return Ok((conn, opened_path));
    }

    let archive = collect_doctor_archive_inventory(&storage_root);
    if archive.counts() == DoctorInventoryCounts::default() {
        return Ok((conn, opened_path));
    }

    let db = match collect_doctor_db_inventory(&conn) {
        Ok(db) => db,
        Err(error) => {
            if doctor_archive_is_authoritative_for_sqlite_path(
                Path::new(&opened_path),
                &storage_root,
                storage_root_is_explicit,
            ) {
                tracing::warn!(
                    source = %opened_path,
                    storage_root = %storage_root.display(),
                    error = %error,
                    "reconstructing sqlite from archive because the live inventory probe failed"
                );
                drop(conn);
                let _mailbox_mutation_locks = if acquire_mutation_locks {
                    Some(acquire_cli_mailbox_mutation_locks(
                        database_url,
                        storage_root_override,
                    )?)
                } else {
                    None
                };
                reconcile_sqlite_file_with_archive(Path::new(&opened_path), &storage_root)?;
                return open_sqlite_with_fallback_and_storage_root(
                    &opened_path,
                    Some(&storage_root),
                );
            }
            return Err(error);
        }
    };
    if !doctor_archive_is_authoritative_for_db(
        &archive,
        &db,
        Path::new(&opened_path),
        &storage_root,
        storage_root_is_explicit,
    ) {
        return Ok((conn, opened_path));
    }
    if doctor_archive_db_drift_detail(&archive, &db).is_none() {
        return Ok((conn, opened_path));
    }

    drop(conn);
    let _mailbox_mutation_locks = if acquire_mutation_locks {
        Some(acquire_cli_mailbox_mutation_locks(
            database_url,
            storage_root_override,
        )?)
    } else {
        None
    };
    reconcile_sqlite_file_with_archive(Path::new(&opened_path), &storage_root)?;
    open_sqlite_with_fallback_and_storage_root(&opened_path, Some(&storage_root))
}

fn open_db_sync_while_holding_mailbox_lock() -> CliResult<mcp_agent_mail_db::DbConn> {
    let cfg = mcp_agent_mail_db::DbPoolConfig::from_env();
    open_db_sync_with_database_url_and_storage_root_locked(&cfg.database_url, None)
}

fn open_db_sync_read_only_with_database_url_and_path(
    database_url: &str,
) -> CliResult<(mcp_agent_mail_db::DbConn, String)> {
    let cfg = mcp_agent_mail_db::DbPoolConfig {
        database_url: database_url.to_string(),
        ..Default::default()
    };
    let path = cfg
        .sqlite_path()
        .map_err(|e| CliError::Other(format!("bad database URL: {e}")))?;
    let path = resolve_sqlite_path_with_absolute_candidate(&path);
    open_sqlite_read_only_with_fallback(&path)
}

fn open_db_sync_read_only_with_database_url(
    database_url: &str,
) -> CliResult<mcp_agent_mail_db::DbConn> {
    open_db_sync_read_only_with_database_url_and_path(database_url).map(|(conn, _opened_path)| conn)
}

fn resolve_read_only_sqlite_source_path_with_database_url(
    database_url: &str,
) -> CliResult<PathBuf> {
    let cfg = mcp_agent_mail_db::DbPoolConfig {
        database_url: database_url.to_string(),
        ..Default::default()
    };
    let path = cfg
        .sqlite_path()
        .map_err(|e| CliError::Other(format!("bad database URL: {e}")))?;
    let path = resolve_sqlite_path_with_absolute_candidate(&path);
    if path == ":memory:" || !Path::new(&path).exists() {
        return Ok(PathBuf::from(path));
    }
    let (conn, opened_path) = open_db_sync_read_only_with_database_url_and_path(database_url)?;
    drop(conn);
    Ok(PathBuf::from(opened_path))
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CanonicalSnapshotSourceKind {
    LiveSqlite,
    LiveSnapshot,
    ArchiveSnapshot,
}

#[derive(Debug)]
struct CanonicalSnapshotSource {
    actual_path: PathBuf,
    reported_path: PathBuf,
    kind: CanonicalSnapshotSourceKind,
    _snapshot_dir: Option<tempfile::TempDir>,
}

impl CanonicalSnapshotSource {
    fn live(path: PathBuf) -> Self {
        Self {
            actual_path: path.clone(),
            reported_path: path,
            kind: CanonicalSnapshotSourceKind::LiveSqlite,
            _snapshot_dir: None,
        }
    }

    fn archive_snapshot(
        reported_path: PathBuf,
        storage_root: &Path,
        salvage_db_path: Option<&Path>,
        context: &str,
    ) -> CliResult<Self> {
        let snapshot_dir = tempfile::Builder::new()
            .prefix("canonical-mailbox-snapshot-")
            .tempdir()
            .map_err(|e| {
                CliError::Other(format!("{context} archive snapshot tempdir failed: {e}"))
            })?;
        let actual_path = snapshot_dir.path().join("mailbox.sqlite3");
        let reconstruct = salvage_db_path
            .filter(|path| path_is_real_file(path))
            .map_or_else(
                || mcp_agent_mail_db::reconstruct_from_archive(&actual_path, storage_root),
                |salvage_db_path| {
                    mcp_agent_mail_db::reconstruct_from_archive_with_salvage(
                        &actual_path,
                        storage_root,
                        Some(salvage_db_path),
                    )
                },
            );
        reconstruct.map_err(|e| {
            CliError::Other(format!(
                "{context} archive snapshot reconstruction failed: {e}"
            ))
        })?;
        Ok(Self {
            actual_path,
            reported_path,
            kind: CanonicalSnapshotSourceKind::ArchiveSnapshot,
            _snapshot_dir: Some(snapshot_dir),
        })
    }

    fn live_snapshot(reported_path: PathBuf, source_path: &Path, context: &str) -> CliResult<Self> {
        let snapshot_dir = tempfile::Builder::new()
            .prefix("canonical-mailbox-live-snapshot-")
            .tempdir()
            .map_err(|e| CliError::Other(format!("{context} live snapshot tempdir failed: {e}")))?;
        let actual_path = snapshot_dir.path().join("mailbox.sqlite3");
        mcp_agent_mail_share::create_sqlite_snapshot(source_path, &actual_path, false)
            .map_err(|e| CliError::Other(format!("{context} live sqlite snapshot failed: {e}")))?;
        Ok(Self {
            actual_path,
            reported_path,
            kind: CanonicalSnapshotSourceKind::LiveSnapshot,
            _snapshot_dir: Some(snapshot_dir),
        })
    }

    fn live_full_sqlite_snapshot(
        reported_path: PathBuf,
        source_path: &Path,
        context: &str,
    ) -> CliResult<Self> {
        let snapshot_dir = tempfile::Builder::new()
            .prefix("canonical-mailbox-full-snapshot-")
            .tempdir()
            .map_err(|e| CliError::Other(format!("{context} full snapshot tempdir failed: {e}")))?;
        let actual_path = snapshot_dir.path().join("mailbox.sqlite3");
        vacuum_into_sqlite_snapshot(source_path, &actual_path, context)?;
        Ok(Self {
            actual_path,
            reported_path,
            kind: CanonicalSnapshotSourceKind::LiveSnapshot,
            _snapshot_dir: Some(snapshot_dir),
        })
    }

    fn actual_path(&self) -> &Path {
        &self.actual_path
    }

    fn reported_path(&self) -> &Path {
        &self.reported_path
    }

    fn uses_archive_snapshot(&self) -> bool {
        matches!(self.kind, CanonicalSnapshotSourceKind::ArchiveSnapshot)
    }

    fn materialize_for_async_read_pool(self, context: &str) -> CliResult<Self> {
        if matches!(
            self.kind,
            CanonicalSnapshotSourceKind::ArchiveSnapshot
                | CanonicalSnapshotSourceKind::LiveSnapshot
        ) {
            return Ok(self);
        }
        let reported_path = self.reported_path;
        let actual_path = self.actual_path;
        Self::live_snapshot(reported_path, &actual_path, context)
    }
}

fn sqlite_string_literal(value: &str) -> String {
    format!("'{}'", value.replace('\'', "''"))
}

fn vacuum_into_sqlite_snapshot(source: &Path, destination: &Path, context: &str) -> CliResult<()> {
    if destination.exists() {
        return Err(CliError::Other(format!(
            "{context} full snapshot destination already exists: {}",
            destination.display()
        )));
    }
    if let Some(parent) = destination.parent()
        && !parent.as_os_str().is_empty()
    {
        std::fs::create_dir_all(parent).map_err(|error| {
            CliError::Other(format!(
                "{context} full snapshot parent creation failed for {}: {error}",
                parent.display()
            ))
        })?;
    }
    let source_str = source.display().to_string();
    let conn = mcp_agent_mail_db::CanonicalDbConn::open_file(&source_str).map_err(|error| {
        CliError::Other(format!(
            "{context} full snapshot source open failed for {}: {error}",
            source.display()
        ))
    })?;
    let destination_literal = sqlite_string_literal(&destination.display().to_string());
    conn.execute_raw(&format!("VACUUM INTO {destination_literal}"))
        .map_err(|error| {
            CliError::Other(format!(
                "{context} full snapshot failed from {} to {}: {error}",
                source.display(),
                destination.display()
            ))
        })?;
    Ok(())
}

fn resolve_canonical_snapshot_source_path(
    source_candidate: &Path,
    storage_root: &Path,
    storage_root_is_explicit: bool,
    context: &str,
) -> CliResult<CanonicalSnapshotSource> {
    let archive = collect_doctor_archive_inventory(storage_root);
    let archive_has_state = archive.counts() != DoctorInventoryCounts::default();
    let candidate_display = source_candidate.display().to_string();
    let candidate_path = PathBuf::from(source_candidate);
    let archive_authoritative_for_path = doctor_archive_is_authoritative_for_sqlite_path(
        source_candidate,
        storage_root,
        storage_root_is_explicit,
    );

    if candidate_display == ":memory:" || !source_candidate.exists() {
        if archive_has_state && archive_authoritative_for_path {
            tracing::warn!(
                operation = context,
                source = candidate_display,
                storage_root = %storage_root.display(),
                "using canonical archive snapshot because the live sqlite source is unavailable"
            );
            return CanonicalSnapshotSource::archive_snapshot(
                candidate_path,
                storage_root,
                None,
                context,
            );
        }
        return Err(CliError::Other(format!(
            "database not found: {}",
            source_candidate.display()
        )));
    }

    match open_sqlite_read_only_with_fallback(&candidate_display) {
        Ok((conn, opened_path)) => {
            let opened_path = PathBuf::from(opened_path);
            let db_inventory = collect_doctor_db_inventory(&conn);
            drop(conn);

            match db_inventory {
                Ok(db_inventory) => {
                    if archive_has_state
                        && doctor_archive_is_authoritative_for_db(
                            &archive,
                            &db_inventory,
                            &opened_path,
                            storage_root,
                            storage_root_is_explicit,
                        )
                        && let Some(detail) =
                            doctor_archive_db_drift_detail(&archive, &db_inventory)
                    {
                        tracing::warn!(
                            operation = context,
                            source = %opened_path.display(),
                            storage_root = %storage_root.display(),
                            drift = detail,
                            "using canonical archive snapshot because the live sqlite index lags the Git archive"
                        );
                        let salvage_path = opened_path.clone();
                        return CanonicalSnapshotSource::archive_snapshot(
                            opened_path,
                            storage_root,
                            Some(salvage_path.as_path()),
                            context,
                        );
                    }
                    Ok(CanonicalSnapshotSource::live(opened_path))
                }
                Err(error) if archive_has_state && archive_authoritative_for_path => {
                    tracing::warn!(
                        operation = context,
                        source = %opened_path.display(),
                        storage_root = %storage_root.display(),
                        error = %error,
                        "using canonical archive snapshot because the live sqlite inventory probe failed"
                    );
                    let salvage_path = opened_path.clone();
                    CanonicalSnapshotSource::archive_snapshot(
                        opened_path,
                        storage_root,
                        Some(salvage_path.as_path()),
                        context,
                    )
                }
                Err(error) => Err(error),
            }
        }
        Err(error) if archive_has_state && archive_authoritative_for_path => {
            tracing::warn!(
                operation = context,
                source = candidate_display,
                storage_root = %storage_root.display(),
                error = %error,
                "using canonical archive snapshot because the live sqlite source could not be opened read-only"
            );
            let salvage_path = candidate_path.clone();
            CanonicalSnapshotSource::archive_snapshot(
                candidate_path,
                storage_root,
                Some(salvage_path.as_path()),
                context,
            )
        }
        Err(error) => Err(error),
    }
}

fn resolve_canonical_snapshot_source_with_database_url(
    database_url: &str,
    storage_root: &Path,
    storage_root_is_explicit: bool,
    context: &str,
) -> CliResult<CanonicalSnapshotSource> {
    let source_candidate = resolve_read_only_sqlite_source_path_with_database_url(database_url)?;
    resolve_canonical_snapshot_source_path(
        &source_candidate,
        storage_root,
        storage_root_is_explicit,
        context,
    )
}

