fn open_db_sync_async_canonical_read_best_effort_with_database_url(
    database_url: &str,
    storage_root_override: Option<&Path>,
    context: &str,
) -> CliResult<CanonicalReadDbPool> {
    let storage_root = resolve_mailbox_activity_storage_root(storage_root_override);
    let storage_root_is_explicit =
        mailbox_activity_storage_root_is_explicit(&storage_root, storage_root_override);
    // Live-current mailboxes can be searched directly without materializing a
    // temp snapshot, which keeps robot search fast under a live server.
    let source = resolve_canonical_snapshot_source_with_database_url(
        database_url,
        &storage_root,
        storage_root_is_explicit,
        context,
    )?;
    let source_path = source.actual_path().display().to_string();
    let (conn, _opened_path) = open_sqlite_read_only_with_fallback(&source_path)?;
    let mut pool_cfg = mcp_agent_mail_db::DbPoolConfig::from_env();
    pool_cfg.database_url = format!("sqlite:///{}", source.actual_path().display());
    pool_cfg.storage_root = Some(storage_root);
    pool_cfg.run_migrations = false;
    pool_cfg.warmup_connections = 0;
    let pool = mcp_agent_mail_db::create_pool_without_startup_init(&pool_cfg)
        .map_err(|e| CliError::Other(format!("db pool init failed: {e}")))?;
    Ok(CanonicalReadDbPool {
        conn,
        pool,
        _source: source,
        _mailbox_read_locks: CliMailboxReadLocks {
            _storage_root_lock: None,
            _sqlite_lock: None,
        },
    })
}

fn open_atc_simulate_read_pool_with_database_url(
    database_url: &str,
    storage_root_override: Option<&Path>,
) -> CliResult<CanonicalReadDbPool> {
    let storage_root = resolve_mailbox_activity_storage_root(storage_root_override);
    let source_candidate =
        resolve_existing_sqlite_source_candidate_with_database_url(database_url, "ATC simulate")?;
    let mailbox_read_locks = acquire_cli_mailbox_read_locks_for_sqlite_path(&source_candidate)?;
    let opened_path = validated_live_sqlite_snapshot_source_path_from_candidate(
        &source_candidate,
        "ATC simulate",
    )?;
    let source = CanonicalSnapshotSource::live_full_sqlite_snapshot(
        opened_path.clone(),
        &opened_path,
        "ATC simulate",
    )?;
    // ATC experiences live in the atc.sqlite3 SIDECAR next to the primary DB
    // (br-bvq1x.11.7), and the replay pool below derives its sidecar path from
    // the SNAPSHOT location — so the sidecar must be snapshotted alongside the
    // primary or simulate silently replays zero experiences. A missing live
    // sidecar is legitimate (no ATC data yet): the replay then sees none.
    let live_sidecar = PathBuf::from(mcp_agent_mail_db::pool::atc_sidecar_sqlite_path(
        &opened_path.display().to_string(),
    ));
    if live_sidecar.is_file() {
        let snapshot_sidecar = source.actual_path().with_file_name("atc.sqlite3");
        vacuum_into_sqlite_snapshot(&live_sidecar, &snapshot_sidecar, "ATC simulate sidecar")?;
    }
    let source_path = source.actual_path().display().to_string();
    let (conn, _opened_path) = open_sqlite_read_only_with_fallback(&source_path)?;
    let mut pool_cfg = mcp_agent_mail_db::DbPoolConfig::from_env();
    pool_cfg.database_url = format!("sqlite:///{}", source.actual_path().display());
    pool_cfg.storage_root = Some(storage_root);
    pool_cfg.run_migrations = false;
    pool_cfg.warmup_connections = 0;
    let pool = mcp_agent_mail_db::create_pool_without_startup_init(&pool_cfg)
        .map_err(|e| CliError::Other(format!("db pool init failed: {e}")))?;
    Ok(CanonicalReadDbPool {
        conn,
        pool,
        _source: source,
        _mailbox_read_locks: mailbox_read_locks,
    })
}

